pub fn run_init(args: &InitArgs) -> anyhow::Result<()> {
    let report = init_project(args.project(), args.force(), args.dry_run())?;
    print_json_or_text(&report, false);
    Ok(())
}

pub fn run_setup(args: &SetupArgs) -> anyhow::Result<()> {
    let report = setup_claude_integration(args)?;
    if args.json() {
        println!("{}", serde_json::to_string_pretty(&report)?);
    } else {
        print_setup_summary(&report);
    }
    Ok(())
}

pub fn run_doctor(args: &DoctorArgs) -> anyhow::Result<()> {
    let report = collect_doctor_report(args.project(), args.full())?;
    let runtime_blocked = report.runtime_drift.status == "blocked";
    let config_blocked = report
        .configured_targets
        .iter()
        .filter(|target| target.configured)
        .any(|target| target.status == "blocked");
    print_json_or_text(&report, args.json());
    if runtime_blocked {
        bail!(
            "runtime drift blocked: {}",
            report.runtime_drift.reasons.join("; ")
        );
    }
    if config_blocked {
        let reasons = report
            .configured_targets
            .iter()
            .filter(|target| target.status == "blocked")
            .flat_map(|target| target.reasons.iter().cloned())
            .collect::<Vec<_>>();
        bail!("MCP config drift blocked: {}", reasons.join("; "));
    }
    Ok(())
}

pub fn run_search(args: &SearchArgs) -> anyhow::Result<()> {
    let results = match try_forward_search(args) {
        Ok(Some(results)) => results,
        Ok(None) => search_for_cli(args)?,
        Err(error) => {
            if args.forward_socket().is_some() {
                return Err(error).context("explicit CLI search forward failed");
            }
            tracing::debug!("CLI search forward failed; falling back to local search: {error}");
            search_for_cli(args)?
        }
    };
    if args.json() {
        println!("{}", serde_json::to_string_pretty(&results)?);
    } else {
        print_search_text(args.query(), &results);
    }
    Ok(())
}

