pub fn run_research(args: &ResearchArgs) -> anyhow::Result<()> {
    match args.command() {
        ResearchCommand::Signal(signal_args) => {
            let result = run_research_signal(signal_args)?;
            render_research_result(&result, signal_args.json())
        }
        ResearchCommand::Schedule(schedule_args) => {
            let result = run_research_schedule(schedule_args)?;
            render_research_result(&result, schedule_args.json())
        }
        ResearchCommand::RunPending(run_args) => {
            let result = run_research_pending(run_args)?;
            render_research_result(&result, run_args.json())
        }
        ResearchCommand::RunBatch(batch_args) => {
            let result = run_research_batch(batch_args)?;
            render_research_result(&result, batch_args.json())
        }
        ResearchCommand::Aggregate(aggregate_args) => {
            let result = run_research_aggregate(aggregate_args)?;
            render_research_result(&result, aggregate_args.json())
        }
        ResearchCommand::MetricDiff(diff_args) => {
            let result = run_research_metric_diff(diff_args)?;
            render_research_result(&result, diff_args.json())
        }
        ResearchCommand::GeminiAuth(auth_args) => {
            let result = run_research_gemini_auth(auth_args)?;
            let ready = result
                .get("ready")
                .and_then(Value::as_bool)
                .unwrap_or(false);
            render_research_result(&result, auth_args.json())?;
            if auth_args.check() && !ready {
                let failure = result
                    .get("failure")
                    .and_then(Value::as_str)
                    .unwrap_or("unknown");
                bail!("Gemini CLI auth is not ready for unattended autoresearch: {failure}");
            }
            Ok(())
        }
        ResearchCommand::State(state_args) => {
            let result = research_state_for_cli(state_args)?;
            render_research_result(&result, state_args.json())
        }
    }
}

