pub fn run_mine_convos(args: &MineConvosArgs) -> anyhow::Result<()> {
    let target = expand_mine_convos_user_path(args.path());
    let collected = collect_mine_convos(&target, args.max_exchanges())?;
    render_mine_convos_report(&collected);

    if args.dry_run() {
        println!("Dry run - no memories written");
        for (_, exchange) in collected.exchanges.iter().take(3) {
            println!("  Q: {}", preview_text(&exchange.user_text, 80));
        }
        return Ok(());
    }

    if collected.exchanges.is_empty() {
        println!("No exchanges to import");
        return Ok(());
    }

    let report = import_mine_convos_for_cli(args, &collected)?;
    print_mine_convos_import_report(&report);
    Ok(())
}

