pub fn run_consolidate(args: &ConsolidateArgs) -> anyhow::Result<()> {
    match args.command() {
        ConsolidateCommand::NowMs => {
            let millis = std::time::SystemTime::now()
                .duration_since(UNIX_EPOCH)
                .context("system clock is before Unix epoch")?
                .as_millis();
            println!("{millis}");
        }
        ConsolidateCommand::StrengthenPrune(stage_args) => {
            run_consolidate_strengthen_prune(stage_args)?;
        }
        ConsolidateCommand::Connect(connect_args) => {
            run_consolidate_connect(connect_args)?;
        }
        ConsolidateCommand::Chain(chain_args) => {
            run_consolidate_chain(chain_args)?;
        }
        ConsolidateCommand::Accuracy(accuracy_args) => {
            run_consolidate_accuracy(accuracy_args)?;
        }
        ConsolidateCommand::Synapse(synapse_args) => {
            run_consolidate_synapse(synapse_args)?;
        }
        ConsolidateCommand::CandidateTtl(ttl_args) => {
            run_consolidate_candidate_ttl(ttl_args)?;
        }
        ConsolidateCommand::RefreshPlaybooks(refresh_args) => {
            run_consolidate_refresh_playbooks(refresh_args)?;
        }
        ConsolidateCommand::RefreshExperience(refresh_args) => {
            run_consolidate_refresh_experience(refresh_args)?;
        }
        ConsolidateCommand::Runtime(runtime_args) => {
            run_consolidate_runtime(runtime_args)?;
        }
        ConsolidateCommand::RealityCheck(reality_args) => {
            run_consolidate_reality_check(reality_args)?;
        }
        ConsolidateCommand::Dream(dream_args) => {
            run_consolidate_dream(dream_args)?;
        }
        ConsolidateCommand::DreamEvolve(evolve_args) => {
            run_consolidate_dream_evolve(evolve_args)?;
        }
        ConsolidateCommand::BuildSummary(summary_args) => {
            let report = build_consolidation_summary(summary_args)?;
            if let Some(parent) = summary_args.summary_json().parent() {
                fs::create_dir_all(parent)
                    .with_context(|| format!("creating summary dir {}", parent.display()))?;
            }
            fs::write(
                summary_args.summary_json(),
                serde_json::to_string_pretty(&report)? + "\n",
            )
            .with_context(|| format!("writing {}", summary_args.summary_json().display()))?;
            if report.phase6_observability.threshold_breached {
                eprintln!(
                    "[phase6_observability] alert_mode={} breached thresholds: {}",
                    report.phase6_observability.alert_mode,
                    serde_json::to_string(&report.phase6_observability.alerts)?
                );
            }
            if report.phase6_observability.alert_mode == "fail"
                && report.phase6_observability.threshold_breached
            {
                std::process::exit(3);
            }
        }
    }
    Ok(())
}

