#[derive(Debug, Clone, PartialEq, Eq)]
struct MineConvosFileReport {
    path: PathBuf,
    exchange_count: usize,
    error: Option<String>,
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct MineConvosCollected {
    target: PathBuf,
    files: Vec<MineConvosFileReport>,
    exchanges: Vec<(PathBuf, Exchange)>,
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct MineConvosImportReport {
    project: String,
    room: Option<String>,
    total_exchanges: usize,
    written: usize,
    duplicates: usize,
    skipped_short: usize,
    errors: usize,
    error_samples: Vec<String>,
}

fn collect_mine_convos(target: &Path, max_exchanges: usize) -> anyhow::Result<MineConvosCollected> {
    if !target.exists() {
        bail!("Not found: {}", target.display());
    }

    let files = conversation_export_files(target)?;
    let mut reports = Vec::new();
    let mut all_exchanges = Vec::new();

    for file in files {
        match normalize_conversation(&file) {
            Ok(exchanges) => {
                let exchange_count = exchanges.len();
                let remaining = max_exchanges.saturating_sub(all_exchanges.len());
                if remaining > 0 {
                    all_exchanges.extend(
                        exchanges
                            .into_iter()
                            .take(remaining)
                            .map(|exchange| (file.clone(), exchange)),
                    );
                }
                reports.push(MineConvosFileReport {
                    path: file,
                    exchange_count,
                    error: None,
                });
            }
            Err(error) => {
                reports.push(MineConvosFileReport {
                    path: file,
                    exchange_count: 0,
                    error: Some(error.to_string()),
                });
            }
        }

        if all_exchanges.len() >= max_exchanges {
            break;
        }
    }

    Ok(MineConvosCollected {
        target: target.to_path_buf(),
        files: reports,
        exchanges: all_exchanges,
    })
}

fn conversation_export_files(target: &Path) -> anyhow::Result<Vec<PathBuf>> {
    if target.is_file() {
        return Ok(vec![target.to_path_buf()]);
    }
    if !target.is_dir() {
        bail!("Not a file or directory: {}", target.display());
    }

    let mut files = Vec::new();
    for extension in ["jsonl", "json", "txt", "md"] {
        let mut matching = fs::read_dir(target)
            .with_context(|| format!("reading {}", target.display()))?
            .filter_map(Result::ok)
            .map(|entry| entry.path())
            .filter(|path| path.is_file())
            .filter(|path| {
                path.extension()
                    .and_then(|value| value.to_str())
                    .map(|value| value.eq_ignore_ascii_case(extension))
                    .unwrap_or(false)
            })
            .collect::<Vec<_>>();
        matching.sort();
        files.extend(matching);
    }
    Ok(files)
}

fn render_mine_convos_report(collected: &MineConvosCollected) {
    if collected.files.is_empty() {
        println!("No supported files found in {}", collected.target.display());
        return;
    }

    println!(
        "Mining {} file(s) from {}",
        collected.files.len(),
        collected.target.display()
    );
    println!();
    for file in &collected.files {
        let name = file
            .path
            .file_name()
            .and_then(|name| name.to_str())
            .unwrap_or("<unknown>");
        if let Some(error) = &file.error {
            println!("  ERR {name}: {error}");
        } else {
            println!("  OK  {name}: {} exchanges", file.exchange_count);
        }
    }
    println!();
    println!("Total: {} exchanges", collected.exchanges.len());
}

fn import_mine_convos_for_cli(
    args: &MineConvosArgs,
    collected: &MineConvosCollected,
) -> anyhow::Result<MineConvosImportReport> {
    let project = resolve_project_id(args.project());
    let db_path = args
        .db_path()
        .map(Path::to_path_buf)
        .unwrap_or_else(|| project_db_path(&project));
    bootstrap_database(&db_path)?;
    let pool = DbPool::open(&db_path)
        .with_context(|| format!("opening database {}", db_path.display()))?;
    let cold_storage = if cli_cold_storage_enabled(args.db_path().is_some()) {
        ColdStorageWriter::new(cold_storage_project_dir(&project), project.clone())
    } else {
        ColdStorageWriter::disabled()
    };
    let writer = WriteOrchestrator::new(pool, cold_storage, project.clone());

    let mut report = MineConvosImportReport {
        project: project.clone(),
        room: args.room().map(str::to_string),
        total_exchanges: collected.exchanges.len(),
        written: 0,
        duplicates: 0,
        skipped_short: 0,
        errors: 0,
        error_samples: Vec::new(),
    };

    for (_source_file, exchange) in &collected.exchanges {
        let content = mine_convos_memory_content(exchange);
        if content.chars().count() < 20 {
            report.skipped_short += 1;
            continue;
        }

        let result = writer.add_memory(&AddMemoryParams {
            content,
            layer: Some("verified_fact".to_string()),
            category: Some("event".to_string()),
            confidence: Some(0.7),
            agent: Some("cli".to_string()),
            room: args.room().map(str::to_string),
            source: Some("convo_miner".to_string()),
            auto_classify: true,
            ..AddMemoryParams::default()
        });
        match result {
            AddMemoryResult::Saved { .. } => report.written += 1,
            AddMemoryResult::Duplicate { .. } => report.duplicates += 1,
            AddMemoryResult::PolicySkipped { reason, .. } => {
                report.errors += 1;
                if report.error_samples.len() < 3 {
                    report.error_samples.push(reason);
                }
            }
            AddMemoryResult::Error(error) => {
                report.errors += 1;
                if report.error_samples.len() < 3 {
                    report.error_samples.push(error);
                }
            }
        }
    }

    Ok(report)
}

fn mine_convos_memory_content(exchange: &Exchange) -> String {
    let mut parts = Vec::new();
    if !exchange.user_text.is_empty() {
        parts.push(format!("Q: {}", exchange.user_text));
    }
    if !exchange.assistant_text.is_empty() {
        parts.push(format!(
            "A: {}",
            truncate_mine_convos_assistant(&exchange.assistant_text)
        ));
    }
    parts.join("\n")
}

fn truncate_mine_convos_assistant(text: &str) -> String {
    let mut chars = text.chars();
    let prefix = chars.by_ref().take(500).collect::<String>();
    if chars.next().is_some() {
        let mut shorter = text.chars().take(497).collect::<String>();
        shorter.push_str("...");
        shorter
    } else {
        prefix
    }
}

fn print_mine_convos_import_report(report: &MineConvosImportReport) {
    println!();
    println!("Done!");
    println!("  Project: {}", report.project);
    if let Some(room) = &report.room {
        println!("  Room: {room}");
    }
    println!("  Total exchanges: {}", report.total_exchanges);
    println!("  Written: {}", report.written);
    println!("  Duplicates skipped: {}", report.duplicates);
    println!("  Short exchanges skipped: {}", report.skipped_short);
    if report.errors > 0 {
        println!("  Errors: {}", report.errors);
        for sample in &report.error_samples {
            println!("    - {sample}");
        }
    }
}

fn expand_mine_convos_user_path(path: &Path) -> PathBuf {
    let raw = path.to_string_lossy();
    if raw == "~" {
        return home_dir();
    }
    if let Some(rest) = raw.strip_prefix("~/") {
        return home_dir().join(rest);
    }
    path.to_path_buf()
}

fn preview_text(text: &str, max_chars: usize) -> String {
    let mut chars = text.chars();
    let preview = chars.by_ref().take(max_chars).collect::<String>();
    if chars.next().is_some() {
        format!("{preview}...")
    } else {
        preview
    }
}

fn search_for_cli(args: &SearchArgs) -> anyhow::Result<Value> {
    let project = resolve_project_id(args.project());
    let db_path = args
        .db_path()
        .map(Path::to_path_buf)
        .unwrap_or_else(|| project_db_path(&project));
    if !db_path.exists() {
        return Ok(json!([]));
    }

    let pool = DbPool::open_readonly(&db_path)
        .with_context(|| format!("opening read-only DB {}", db_path.display()))?;
    let engine = SearchEngine::new(pool);
    let params = search_params_from_cli(args, project);
    Ok(search_results_json(&engine, &params))
}

fn search_params_from_cli(args: &SearchArgs, project: String) -> SearchParams {
    SearchParams {
        query: args.query().to_string(),
        limit: args.limit(),
        layer: args.layer().map(str::to_string),
        category: args.category().map(str::to_string),
        only_active: true,
        agent_id: None,
        project_id: Some(project),
        as_of: None,
        start_time: None,
        end_time: None,
        include_expired: false,
        cross_project: false,
        search_mode: args.search_mode().map(str::to_string),
        room: None,
        min_score: args.min_score(),
        boost_categories: None,
        include_constitution: args.include_constitution(),
    }
}

fn search_params_from_forward_request(request: &CliForwardSearchRequest) -> SearchParams {
    SearchParams {
        query: request.query.clone(),
        limit: request.limit,
        layer: request.layer.clone(),
        category: request.category.clone(),
        only_active: true,
        agent_id: None,
        project_id: Some(request.project.clone()),
        as_of: None,
        start_time: None,
        end_time: None,
        include_expired: false,
        cross_project: false,
        search_mode: request.search_mode.clone(),
        room: None,
        min_score: request.min_score,
        boost_categories: None,
        include_constitution: request.include_constitution,
    }
}

fn search_results_json(engine: &SearchEngine, params: &SearchParams) -> Value {
    let results = engine.search(params);
    Value::Array(
        results
            .into_iter()
            .map(|result| {
                json!({
                    "id": result.id,
                    "score": round4(result.score),
                    "layer": result.layer,
                    "category": result.category,
                    "content": preview_text(&result.content, 200),
                    "created_at": result.created_at,
                    "metadata": result.metadata,
                })
            })
            .collect(),
    )
}

fn cli_daemon_socket_path(project: &str) -> PathBuf {
    cli_daemon_socket_path_at(&ma_home(), project)
}

fn cli_daemon_socket_path_at(ma_home: &Path, project: &str) -> PathBuf {
    let slug = ascii_slug(project);
    let slug = if slug.is_empty() {
        DEFAULT_PROJECT_ID.to_string()
    } else {
        slug
    };
    ma_home.join("run").join(format!("{slug}.sock"))
}

fn cli_forward_search_request(args: &SearchArgs, project: String) -> CliForwardSearchRequest {
    CliForwardSearchRequest {
        command: "search".to_string(),
        project,
        query: args.query().to_string(),
        limit: args.limit(),
        layer: args.layer().map(str::to_string),
        category: args.category().map(str::to_string),
        search_mode: args.search_mode().map(str::to_string),
        min_score: args.min_score(),
        include_constitution: args.include_constitution(),
    }
}

#[cfg(unix)]
fn try_forward_search(args: &SearchArgs) -> anyhow::Result<Option<Value>> {
    if args.no_forward() || args.db_path().is_some() || cli_forward_disabled_by_env() {
        return Ok(None);
    }

    let project = resolve_project_id(args.project());
    let socket_path = args
        .forward_socket()
        .map(Path::to_path_buf)
        .unwrap_or_else(|| cli_daemon_socket_path(&project));
    if !socket_path.exists() {
        if args.forward_socket().is_some() {
            bail!("CLI forward socket not found: {}", socket_path.display());
        }
        return Ok(None);
    }

    let mut stream = match UnixStream::connect(&socket_path) {
        Ok(stream) => stream,
        Err(error) => {
            if args.forward_socket().is_some() {
                return Err(error).with_context(|| {
                    format!(
                        "connecting explicit CLI forward socket {}",
                        socket_path.display()
                    )
                });
            }
            tracing::debug!(
                "CLI search forward socket unavailable at {}: {error}",
                socket_path.display()
            );
            return Ok(None);
        }
    };
    stream.set_read_timeout(Some(StdDuration::from_millis(800)))?;
    stream.set_write_timeout(Some(StdDuration::from_millis(800)))?;

    let request = cli_forward_search_request(args, project);
    let payload = serde_json::to_string(&request)?;
    stream.write_all(payload.as_bytes())?;
    stream.write_all(b"\n")?;
    stream.flush()?;

    let mut reader = BufReader::new(stream);
    let mut line = String::new();
    reader.read_line(&mut line)?;
    if line.trim().is_empty() {
        return Ok(None);
    }

    let response = serde_json::from_str::<CliForwardResponse>(&line)?;
    if response.status == "ok" {
        return Ok(response.results);
    }
    bail!(
        "CLI daemon returned error: {}",
        response.error.unwrap_or_else(|| "unknown".to_string())
    )
}

#[cfg(not(unix))]
fn try_forward_search(_args: &SearchArgs) -> anyhow::Result<Option<Value>> {
    Ok(None)
}

fn cli_forward_disabled_by_env() -> bool {
    env::var("MA_CLI_FORWARD")
        .map(|value| {
            let value = value.trim().to_ascii_lowercase();
            matches!(value.as_str(), "0" | "false" | "off" | "no")
        })
        .unwrap_or(false)
}

#[cfg(unix)]
pub fn serve_cli_daemon(project: Option<&str>, socket: Option<&Path>) -> anyhow::Result<()> {
    let project = resolve_project_id(project);
    let db_path = project_db_path(&project);
    if !db_path.exists() {
        bail!("database not found: {}", db_path.display());
    }

    let pool = DbPool::open_readonly(&db_path)
        .with_context(|| format!("opening read-only DB {}", db_path.display()))?;
    let engine = SearchEngine::new(pool);
    let socket_path = socket
        .map(Path::to_path_buf)
        .unwrap_or_else(|| cli_daemon_socket_path(&project));
    prepare_cli_daemon_socket(&socket_path)?;

    let _ = embed_text("memory anchor daemon warmup");
    let listener = UnixListener::bind(&socket_path)
        .with_context(|| format!("binding CLI daemon socket {}", socket_path.display()))?;
    eprintln!(
        "Memra CLI daemon listening project={} socket={}",
        project,
        socket_path.display()
    );

    for stream in listener.incoming() {
        match stream {
            Ok(stream) => {
                if let Err(error) = handle_cli_daemon_stream(stream, &engine, &project) {
                    eprintln!("CLI daemon request failed: {error:#}");
                }
            }
            Err(error) => eprintln!("CLI daemon accept failed: {error}"),
        }
    }
    Ok(())
}

#[cfg(not(unix))]
pub fn serve_cli_daemon(_project: Option<&str>, _socket: Option<&Path>) -> anyhow::Result<()> {
    bail!("CLI daemon forwarding requires Unix domain socket support")
}

#[cfg(unix)]
fn prepare_cli_daemon_socket(socket_path: &Path) -> anyhow::Result<()> {
    if let Some(parent) = socket_path.parent() {
        fs::create_dir_all(parent)
            .with_context(|| format!("creating CLI daemon socket dir {}", parent.display()))?;
    }
    if !socket_path.exists() {
        return Ok(());
    }

    let metadata = fs::symlink_metadata(socket_path)
        .with_context(|| format!("checking existing socket {}", socket_path.display()))?;
    if metadata.file_type().is_socket() {
        fs::remove_file(socket_path)
            .with_context(|| format!("removing stale socket {}", socket_path.display()))?;
        return Ok(());
    }
    bail!(
        "refusing to replace non-socket path {}",
        socket_path.display()
    )
}

#[cfg(unix)]
fn handle_cli_daemon_stream(
    mut stream: UnixStream,
    engine: &SearchEngine,
    daemon_project: &str,
) -> anyhow::Result<()> {
    let mut reader = BufReader::new(stream.try_clone()?);
    let mut line = String::new();
    reader.read_line(&mut line)?;
    let response = match serde_json::from_str::<CliForwardSearchRequest>(&line) {
        Ok(request) => handle_cli_daemon_request(request, engine, daemon_project),
        Err(error) => CliForwardResponse {
            status: "error".to_string(),
            results: None,
            error: Some(format!("invalid request: {error}")),
        },
    };
    stream.write_all(serde_json::to_string(&response)?.as_bytes())?;
    stream.write_all(b"\n")?;
    stream.flush()?;
    Ok(())
}

fn handle_cli_daemon_request(
    request: CliForwardSearchRequest,
    engine: &SearchEngine,
    daemon_project: &str,
) -> CliForwardResponse {
    if request.command != "search" {
        return CliForwardResponse {
            status: "error".to_string(),
            results: None,
            error: Some(format!("unsupported command: {}", request.command)),
        };
    }
    if request.project != daemon_project {
        return CliForwardResponse {
            status: "error".to_string(),
            results: None,
            error: Some(format!(
                "project mismatch: daemon={} request={}",
                daemon_project, request.project
            )),
        };
    }

    let params = search_params_from_forward_request(&request);
    CliForwardResponse {
        status: "ok".to_string(),
        results: Some(search_results_json(engine, &params)),
        error: None,
    }
}

fn bench_retrieval_for_cli(args: &BenchRetrievalArgs) -> anyhow::Result<BenchRetrievalReport> {
    let project = resolve_project_id(Some(args.project()));
    let db_path = args
        .db_path()
        .map(Path::to_path_buf)
        .unwrap_or_else(|| project_db_path(&project));
    if !db_path.exists() {
        bail!("database not found: {}", db_path.display());
    }

    let queries = bench_queries_from_tsv(args.query_file())?;
    if queries.is_empty() {
        bail!(
            "no benchmark queries found in {}",
            args.query_file().display()
        );
    }

    let pool = DbPool::open_readonly(&db_path)
        .with_context(|| format!("opening read-only DB {}", db_path.display()))?;
    let engine = SearchEngine::new(pool);

    let warmup_params =
        bench_search_params(&project, &queries[0].0, args.limit(), args.min_score());
    let _ = engine.search(&warmup_params);

    let mut latencies = Vec::with_capacity(queries.len());
    let mut results = Vec::with_capacity(queries.len());
    for (index, (query, expected_focus)) in queries.into_iter().enumerate() {
        let params = bench_search_params(&project, &query, args.limit(), args.min_score());
        let started = Instant::now();
        let search_results = engine.search(&params);
        let latency_ms = elapsed_ms(started);
        let top = search_results.first();
        latencies.push(latency_ms);
        results.push(BenchRetrievalItem {
            index: index + 1,
            query,
            expected_focus,
            latency_ms,
            result_count: search_results.len(),
            top1_id: top.map(|result| result.id.clone()),
            top1_score: top.map(|result| round4(result.score)),
            top1_layer: top.map(|result| result.layer.clone()),
            top1_category: top.and_then(|result| result.category.clone()),
            top1_content: top.map(|result| preview_text(&result.content, 800)),
        });
    }

    Ok(BenchRetrievalReport {
        status: "ok".to_string(),
        project,
        db_path: db_path.display().to_string(),
        query_file: args.query_file().display().to_string(),
        query_count: results.len(),
        successful_searches: results.len(),
        latency_ms: bench_latency_report(&latencies),
        results,
    })
}

fn bench_queries_from_tsv(path: &Path) -> anyhow::Result<Vec<(String, String)>> {
    let raw = fs::read_to_string(path).with_context(|| format!("reading {}", path.display()))?;
    let mut queries = Vec::new();
    for (line_index, line) in raw.lines().enumerate() {
        let line_number = line_index + 1;
        let trimmed = line.trim();
        if trimmed.is_empty() || trimmed.starts_with('#') {
            continue;
        }
        let Some((query, expected_focus)) = line.split_once('\t') else {
            bail!(
                "{}:{} expected tab-separated query and expected focus",
                path.display(),
                line_number
            );
        };
        let query = query.trim();
        if query.is_empty() {
            bail!("{}:{} query must not be empty", path.display(), line_number);
        }
        queries.push((query.to_string(), expected_focus.trim().to_string()));
    }
    Ok(queries)
}

fn bench_search_params(project: &str, query: &str, limit: usize, min_score: f64) -> SearchParams {
    SearchParams {
        query: query.to_string(),
        limit,
        layer: None,
        category: None,
        only_active: true,
        agent_id: None,
        project_id: Some(project.to_string()),
        as_of: None,
        start_time: None,
        end_time: None,
        include_expired: false,
        cross_project: false,
        search_mode: None,
        room: None,
        min_score,
        boost_categories: None,
        include_constitution: false,
    }
}

fn elapsed_ms(started: Instant) -> f64 {
    round2(started.elapsed().as_secs_f64() * 1000.0)
}

fn round2(value: f64) -> f64 {
    (value * 100.0).round() / 100.0
}

fn bench_latency_report(values: &[f64]) -> BenchLatencyReport {
    if values.is_empty() {
        return BenchLatencyReport {
            min: None,
            p50: None,
            p95: None,
            p99: None,
            max: None,
            mean: None,
        };
    }

    let mut sorted = values.to_vec();
    sorted.sort_by(f64::total_cmp);
    let mean = values.iter().sum::<f64>() / values.len() as f64;
    BenchLatencyReport {
        min: sorted.first().copied(),
        p50: percentile_ceil(&sorted, 50.0),
        p95: percentile_ceil(&sorted, 95.0),
        p99: percentile_ceil(&sorted, 99.0),
        max: sorted.last().copied(),
        mean: Some(round2(mean)),
    }
}

fn percentile_ceil(sorted_values: &[f64], percentile: f64) -> Option<f64> {
    if sorted_values.is_empty() {
        return None;
    }
    let rank = (percentile / 100.0) * ((sorted_values.len() - 1) as f64);
    let index = (rank.ceil() as usize).min(sorted_values.len() - 1);
    Some(sorted_values[index])
}

#[derive(Debug, Default)]
struct RecallCliExtras {
    confidence: Option<f64>,
    source: Option<String>,
    updated_at: Option<String>,
}

fn recall_for_cli(args: &RecallArgs) -> anyhow::Result<Value> {
    let project = resolve_project_id(Some(args.project_or_user()));
    let db_path = args
        .db_path()
        .map(Path::to_path_buf)
        .unwrap_or_else(|| project_db_path(&project));
    if !db_path.exists() {
        return Ok(json!([]));
    }

    let pool = DbPool::open_readonly(&db_path)
        .with_context(|| format!("opening read-only DB {}", db_path.display()))?;
    let engine = SearchEngine::new(pool);
    let params = SearchParams {
        query: args.query().to_string(),
        limit: args.limit(),
        layer: None,
        category: None,
        only_active: true,
        agent_id: None,
        project_id: Some(project),
        as_of: None,
        start_time: None,
        end_time: None,
        include_expired: false,
        cross_project: false,
        search_mode: None,
        room: None,
        min_score: args.min_score(),
        boost_categories: None,
        include_constitution: true,
    };
    let results = engine.search(&params);
    Ok(Value::Array(
        results
            .into_iter()
            .map(|result| recall_result_json(engine.pool(), result))
            .collect(),
    ))
}

fn recall_result_json(pool: &DbPool, result: SearchResult) -> Value {
    let extras = recall_cli_extras(pool, &result.id);
    json!({
        "id": result.id,
        "content": result.content,
        "layer": result.layer,
        "category": result.category,
        "score": round4(result.score),
        "confidence": extras.confidence,
        "source": extras.source,
        "created_at": result.created_at,
        "updated_at": extras.updated_at,
        "metadata": result.metadata,
    })
}

fn recall_cli_extras(pool: &DbPool, note_id: &str) -> RecallCliExtras {
    pool.with_conn(|conn| {
        conn.query_row(
            "SELECT confidence, source, updated_at FROM notes WHERE id = ?1",
            rusqlite::params![note_id],
            |row| {
                Ok(RecallCliExtras {
                    confidence: row.get::<_, Option<f64>>(0).ok().flatten(),
                    source: row.get::<_, Option<String>>(1).ok().flatten(),
                    updated_at: row.get::<_, Option<String>>(2).ok().flatten(),
                })
            },
        )
        .ok()
    })
    .unwrap_or_default()
}

fn print_search_text(query: &str, results: &Value) {
    let Some(items) = results.as_array() else {
        println!("No results for '{query}'");
        return;
    };
    if items.is_empty() {
        println!("No results for '{query}'");
        return;
    }
    for (index, item) in items.iter().enumerate() {
        let layer = item.get("layer").and_then(Value::as_str).unwrap_or("");
        let score = item.get("score").and_then(Value::as_f64).unwrap_or(0.0);
        let content = item.get("content").and_then(Value::as_str).unwrap_or("");
        let id = item
            .get("id")
            .and_then(Value::as_str)
            .map(|id| prefix_chars(id, 8))
            .unwrap_or_default();
        println!(
            "{}. [{}] (score: {:.4}) {} ({})",
            index + 1,
            layer,
            score,
            content,
            id
        );
    }
}

fn print_recall_text(query: &str, results: &Value) {
    let Some(items) = results.as_array() else {
        println!("No memories for '{query}'");
        return;
    };
    if items.is_empty() {
        println!("No memories for '{query}'");
        return;
    }
    for (index, item) in items.iter().enumerate() {
        let layer = item.get("layer").and_then(Value::as_str).unwrap_or("");
        let score = item.get("score").and_then(Value::as_f64).unwrap_or(0.0);
        let content = item.get("content").and_then(Value::as_str).unwrap_or("");
        let id = item
            .get("id")
            .and_then(Value::as_str)
            .map(|id| prefix_chars(id, 8))
            .unwrap_or_default();
        println!(
            "{}. [{}] (score: {:.4}) {} ({})",
            index + 1,
            layer,
            score,
            preview_text(content, 80).replace('\n', " "),
            id
        );
    }
}

