fn confirm_for_cli(args: &ConfirmArgs) -> anyhow::Result<Value> {
    let db_path = args
        .db_path()
        .map(Path::to_path_buf)
        .unwrap_or_else(|| project_db_path(args.project()));
    if !db_path.exists() {
        bail!("database not found: {}", db_path.display());
    }
    let conn = Connection::open(&db_path)
        .with_context(|| format!("opening database {}", db_path.display()))?;
    ensure_notes_trust_columns(&conn)?;

    if let Some(memory_id) = args.memory_id() {
        return confirm_one_for_cli(&conn, args, memory_id);
    }

    confirm_batch_for_cli(&conn, args)
}

fn confirm_one_for_cli(
    conn: &Connection,
    args: &ConfirmArgs,
    memory_id: &str,
) -> anyhow::Result<Value> {
    let now = Utc::now().timestamp();
    let confirmed_by = confirm_actor();
    let changed = conn.execute(
        "UPDATE notes
         SET confirmed_at = ?1, confirmed_by = ?2
         WHERE id = ?3",
        params![now, confirmed_by, memory_id],
    )?;
    let status = if changed == 0 {
        "not_found"
    } else {
        "confirmed"
    };
    let text = if changed == 0 {
        format!("No note found for id {memory_id}")
    } else {
        format!("Confirmed {memory_id}")
    };
    Ok(json!({
        "status": status,
        "project": args.project(),
        "memory_id": memory_id,
        "confirmed_count": changed,
        "confirmed_by": confirmed_by,
        "text": text,
    }))
}

fn confirm_batch_for_cli(conn: &Connection, args: &ConfirmArgs) -> anyhow::Result<Value> {
    let since = parse_confirm_since(args.since().unwrap_or("24h"))?;
    let cutoff = (Utc::now() - since).timestamp();
    let candidates = load_confirm_candidates(conn, args.source(), cutoff)?;
    if candidates.is_empty() {
        return Ok(json!({
            "status": "empty",
            "project": args.project(),
            "source": args.source(),
            "candidate_count": 0,
            "confirmed_count": 0,
            "text": "No candidates to confirm",
        }));
    }

    if args.dry_run() {
        return Ok(confirm_batch_report(
            "dry_run",
            args,
            &candidates,
            0,
            "Dry run: no candidates confirmed",
        ));
    }

    if !args.yes() && !confirm_batch_prompt(&candidates)? {
        return Ok(confirm_batch_report(
            "skipped",
            args,
            &candidates,
            0,
            "Confirmation skipped",
        ));
    }

    let now = Utc::now().timestamp();
    let confirmed_by = confirm_actor();
    let tx = conn.unchecked_transaction()?;
    let mut changed = 0usize;
    for candidate in &candidates {
        changed += tx.execute(
            "UPDATE notes
             SET confirmed_at = ?1, confirmed_by = ?2
             WHERE id = ?3 AND confirmed_at IS NULL",
            params![now, confirmed_by, candidate.id],
        )?;
    }
    tx.commit()?;

    Ok(confirm_batch_report(
        "confirmed",
        args,
        &candidates,
        changed,
        &format!("Confirmed {changed} candidate(s)"),
    ))
}

#[derive(Debug, Clone, PartialEq, Eq, Serialize)]
struct ConfirmCandidate {
    id: String,
    content: String,
    source: String,
    created_at: Option<String>,
}

fn load_confirm_candidates(
    conn: &Connection,
    source: &str,
    cutoff_epoch: i64,
) -> anyhow::Result<Vec<ConfirmCandidate>> {
    let mut stmt = conn.prepare(
        "SELECT id, content, COALESCE(source, ''), created_at
         FROM notes
         WHERE source = ?1
           AND confirmed_at IS NULL
           AND COALESCE(is_active, 1) = 1
           AND COALESCE(
                CASE
                    WHEN typeof(created_at) IN ('integer', 'real') THEN CAST(created_at AS INTEGER)
                    WHEN created_at NOT GLOB '*[^0-9]*' THEN CAST(created_at AS INTEGER)
                    ELSE CAST(strftime('%s', created_at) AS INTEGER)
                END,
                0
           ) >= ?2
         ORDER BY created_at DESC, id ASC",
    )?;
    let rows = stmt.query_map(params![source, cutoff_epoch], |row| {
        Ok(ConfirmCandidate {
            id: row.get(0)?,
            content: row.get(1)?,
            source: row.get(2)?,
            created_at: row.get(3).ok(),
        })
    })?;
    rows.collect::<rusqlite::Result<Vec<_>>>()
        .map_err(Into::into)
}

fn parse_confirm_since(input: &str) -> anyhow::Result<Duration> {
    let trimmed = input.trim();
    if trimmed.is_empty() {
        bail!("--since cannot be empty");
    }
    let (digits, unit) = trimmed.split_at(
        trimmed
            .find(|ch: char| !ch.is_ascii_digit())
            .unwrap_or(trimmed.len()),
    );
    let amount: i64 = digits
        .parse()
        .with_context(|| format!("parsing --since duration {input:?}"))?;
    match unit {
        "" | "h" | "hour" | "hours" => Ok(Duration::hours(amount)),
        "d" | "day" | "days" => Ok(Duration::days(amount)),
        _ => bail!("unsupported --since unit {unit:?}; use h or d"),
    }
}

fn confirm_actor() -> String {
    env::var("USER")
        .ok()
        .filter(|value| !value.trim().is_empty())
        .unwrap_or_else(|| "ma-cli".to_string())
}

fn confirm_batch_prompt(candidates: &[ConfirmCandidate]) -> anyhow::Result<bool> {
    eprintln!("Confirm {} candidate(s)? [y/N]", candidates.len());
    io::stderr().flush().ok();
    let mut answer = String::new();
    io::stdin().read_line(&mut answer)?;
    Ok(matches!(answer.trim(), "y" | "Y" | "yes" | "YES"))
}

