fn record_feedback_for_cli(
    project: &str,
    db_path: &Path,
    memory_id: &str,
    outcome: &str,
    reason: Option<&str>,
) -> Result<bool, String> {
    if !db_path.exists() {
        return Err(format!("database not found: {}", db_path.display()));
    }
    let pool = DbPool::open(db_path)
        .map_err(|error| format!("opening database {}: {error}", db_path.display()))?;
    let writer = WriteOrchestrator::new(pool, ColdStorageWriter::disabled(), project.to_string());
    writer.report_outcome(memory_id, outcome, reason)
}

fn feedback_success_text(memory_id: &str, outcome: &str, reason: Option<&str>) -> String {
    let icon = match outcome {
        "confirmed" => "✅",
        "corrected" => "🔧",
        "outdated" => "🕰️",
        _ => "❓",
    };
    let mut text = format!("{icon} 反馈已记录\n- ID: {memory_id}\n- 结果: {outcome}\n");
    if let Some(reason) = reason {
        text.push_str(&format!("- 说明: {reason}\n"));
    }
    text
}

