fn print_feedback_due_text(report: &Value) {
    let counts = report.get("counts").unwrap_or(&Value::Null);
    let returned = report.get("returned_counts").unwrap_or(&Value::Null);
    let gate = report.get("activation_gate").unwrap_or(&Value::Null);
    println!(
        "Feedback Due - {}",
        report
            .get("project_id")
            .and_then(Value::as_str)
            .unwrap_or(DEFAULT_PROJECT_ID)
    );
    println!(
        "topic feedback: {} | {}/{} in {}d",
        value_i64(counts, "feedback_deficit"),
        value_i64(gate, "recent_feedback_count"),
        value_i64(gate, "target_feedback_count"),
        value_i64(gate, "window_days")
    );
    println!(
        "review_required: {} | showing {}; review_experience(experience_id, force=true)",
        value_i64(counts, "review_required"),
        value_i64(returned, "review_required")
    );
    println!(
        "actions: {} | showing {}; report_outcome(memory_id, outcome, experience_id, action_id)",
        value_i64(counts, "recommended_actions"),
        value_i64(returned, "recommended_actions")
    );
    println!(
        "dream feedback: {} | showing {}; report_outcome(memory_id, outcome)",
        value_i64(counts, "dream_feedback_due"),
        value_i64(returned, "dream_feedback_due")
    );

    for item in report
        .get("review_required")
        .and_then(Value::as_array)
        .into_iter()
        .flatten()
    {
        println!();
        println!(
            "Review due: {}",
            value_str(item, "experience_id")
                .chars()
                .take(12)
                .collect::<String>()
        );
        println!(
            "- state: {}",
            item.get("consensus_state")
                .and_then(Value::as_str)
                .or_else(|| item.get("review_outcome").and_then(Value::as_str))
                .unwrap_or("under_review")
        );
        println!(
            "- blockers: {}",
            item.get("promotion_blockers")
                .and_then(Value::as_array)
                .map(|values| {
                    values
                        .iter()
                        .filter_map(Value::as_str)
                        .collect::<Vec<_>>()
                        .join(", ")
                })
                .filter(|value| !value.is_empty())
                .unwrap_or_else(|| "none".to_string())
        );
        if let Some(next) = item
            .get("next_actions")
            .and_then(Value::as_array)
            .and_then(|values| values.first())
            .and_then(Value::as_str)
        {
            println!("- next: {next}");
        }
        println!("- {}", value_str(item, "suggested_tool"));
    }

    for item in report
        .get("recommended_actions")
        .and_then(Value::as_array)
        .into_iter()
        .flatten()
    {
        println!();
        println!(
            "Action due: {}",
            value_str(item, "action_id")
                .chars()
                .take(12)
                .collect::<String>()
        );
        println!("- memory_id: {}", value_str(item, "memory_id"));
        println!("- target: {}", value_str(item, "target_system"));
        println!("- {}", value_str(item, "summary"));
        println!("- {}", value_str(item, "suggested_tool"));
    }

    for item in report
        .get("dream_feedback_due")
        .and_then(Value::as_array)
        .into_iter()
        .flatten()
    {
        println!();
        println!(
            "Dream feedback: {}",
            value_str(item, "memory_id")
                .chars()
                .take(8)
                .collect::<String>()
        );
        println!("- {}", value_str(item, "summary"));
        println!("- {}", value_str(item, "suggested_tool"));
    }
}

