fn runtime_result_template(dry_run: bool) -> Value {
    json!({
        "promoted": 0,
        "merged": 0,
        "skipped": 0,
        "candidates_found": 0,
        "procedure_candidates_found": 0,
        "procedures_created": 0,
        "procedures_skipped_no_llm": 0,
        "contradiction_fixtures_loaded": 0,
        "contradictions_created": 0,
        "contradictions_updated": 0,
        "old_notes_incremented": 0,
        "hebbian_pairs_observed": 0,
        "hebbian_pairs_above_threshold": 0,
        "hebbian_relations_created": 0,
        "hebbian_relations_strengthened": 0,
        "fallback_stats": {
            "event_writer_missing": 0,
            "event_writer_error_fallback": 0,
            "event_direct_upsert_used": 0,
            "procedure_writer_missing": 0,
            "procedure_writer_error_fallback": 0,
            "procedure_direct_upsert_used": 0,
        },
        "errors": [],
        "dry_run": dry_run,
    })
}

fn consolidate_runtime_dry_run_report(
    conn: &Connection,
    db_path: &Path,
    rust_writer: bool,
) -> anyhow::Result<Value> {
    let candidates_found = runtime_consolidation_candidates(conn)?;
    let procedure_candidates_found = runtime_procedure_candidates(conn)?;
    let mut result = runtime_result_template(true);
    result["candidates_found"] = json!(candidates_found);
    result["procedure_candidates_found"] = json!(procedure_candidates_found);
    result["procedures_skipped_no_llm"] = json!(procedure_candidates_found);
    let runtime_truth = build_runtime_truth_payload(
        db_path,
        rust_writer,
        result
            .as_object()
            .context("runtime result must be object")?,
    );
    result["runtime_truth"] = runtime_truth;
    Ok(result)
}

fn consolidate_runtime_apply_report(
    conn: &Connection,
    db_path: &Path,
    rust_writer: bool,
) -> anyhow::Result<Value> {
    let pool = DbPool::open(db_path)
        .with_context(|| format!("opening runtime writer DB {}", db_path.display()))?;
    let cold_enabled = std::env::var("MA_COLD_STORAGE_ENABLED")
        .map(|value| value != "false" && value != "0")
        .unwrap_or(true);
    let cold_storage = if cold_enabled {
        ColdStorageWriter::new(
            cold_storage_project_dir(DEFAULT_PROJECT_ID),
            DEFAULT_PROJECT_ID.to_string(),
        )
    } else {
        ColdStorageWriter::disabled()
    };
    let writer = WriteOrchestrator::new(pool, cold_storage, DEFAULT_PROJECT_ID.to_string());
    consolidate_runtime_apply_with_writer(conn, db_path, rust_writer, |params| {
        writer.add_memory(params)
    })
}

fn consolidate_runtime_apply_with_writer<F>(
    conn: &Connection,
    db_path: &Path,
    rust_writer: bool,
    mut add_memory: F,
) -> anyhow::Result<Value>
where
    F: FnMut(&AddMemoryParams) -> AddMemoryResult,
{
    let candidates = load_runtime_event_candidates(conn)?;
    let procedure_candidates = load_runtime_procedure_candidates(conn)?;
    let mut result = runtime_result_template(false);
    result["candidates_found"] = json!(candidates.len());
    result["procedure_candidates_found"] = json!(procedure_candidates.len());

    for candidate in candidates {
        match promote_runtime_event(conn, &candidate, &mut add_memory) {
            Ok(RuntimePromotionOutcome::Promoted) => {
                result["promoted"] = json!(result["promoted"].as_i64().unwrap_or(0) + 1);
            }
            Ok(RuntimePromotionOutcome::Merged) => {
                result["merged"] = json!(result["merged"].as_i64().unwrap_or(0) + 1);
            }
            Ok(RuntimePromotionOutcome::Skipped) => {
                result["skipped"] = json!(result["skipped"].as_i64().unwrap_or(0) + 1);
            }
            Err(error) => {
                result["skipped"] = json!(result["skipped"].as_i64().unwrap_or(0) + 1);
                result["fallback_stats"]["event_writer_error_fallback"] = json!(
                    result["fallback_stats"]["event_writer_error_fallback"]
                        .as_i64()
                        .unwrap_or(0)
                        + 1
                );
                if let Some(errors) = result["errors"].as_array_mut() {
                    errors.push(json!(format!(
                        "Failed to consolidate {}: {error}",
                        candidate.id
                    )));
                }
            }
        }
    }

    for candidate in procedure_candidates {
        match promote_runtime_procedure(conn, &candidate, &mut add_memory) {
            Ok(Some(_created_id)) => {
                result["procedures_created"] =
                    json!(result["procedures_created"].as_i64().unwrap_or(0) + 1);
            }
            Ok(None) => {}
            Err(error) => {
                result["fallback_stats"]["procedure_writer_error_fallback"] = json!(
                    result["fallback_stats"]["procedure_writer_error_fallback"]
                        .as_i64()
                        .unwrap_or(0)
                        + 1
                );
                if let Some(errors) = result["errors"].as_array_mut() {
                    errors.push(json!(format!(
                        "Failed to extract procedure for {}: {error}",
                        candidate
                            .topic_key
                            .as_deref()
                            .unwrap_or(candidate.lineage_key.as_str())
                    )));
                }
            }
        }
    }

    match apply_runtime_contradiction_fixtures(conn, None, 20) {
        Ok(contradiction_report) => {
            result["contradiction_fixtures_loaded"] = contradiction_report
                .get("fixtures_loaded")
                .cloned()
                .unwrap_or_else(|| json!(0));
            result["contradictions_created"] = contradiction_report
                .get("contradictions_created")
                .cloned()
                .unwrap_or_else(|| json!(0));
            result["contradictions_updated"] = contradiction_report
                .get("contradictions_updated")
                .cloned()
                .unwrap_or_else(|| json!(0));
            result["old_notes_incremented"] = contradiction_report
                .get("old_notes_incremented")
                .cloned()
                .unwrap_or_else(|| json!(0));
            result["contradiction_fixtures"] = contradiction_report;
        }
        Err(error) => {
            if let Some(errors) = result["errors"].as_array_mut() {
                errors.push(json!(format!(
                    "Failed to apply contradiction fixtures: {error}"
                )));
            }
        }
    }

    match apply_runtime_activation_trace_hebbian(conn, None, None, true) {
        Ok(hebbian_report) => {
            result["hebbian_pairs_observed"] = hebbian_report
                .get("pairs_observed")
                .cloned()
                .unwrap_or_else(|| json!(0));
            result["hebbian_pairs_above_threshold"] = hebbian_report
                .get("pairs_above_threshold")
                .cloned()
                .unwrap_or_else(|| json!(0));
            result["hebbian_relations_created"] = hebbian_report
                .get("relations_created")
                .cloned()
                .unwrap_or_else(|| json!(0));
            result["hebbian_relations_strengthened"] = hebbian_report
                .get("relations_strengthened")
                .cloned()
                .unwrap_or_else(|| json!(0));
            result["activation_trace_hebbian"] = hebbian_report;
        }
        Err(error) => {
            if let Some(errors) = result["errors"].as_array_mut() {
                errors.push(json!(format!(
                    "Failed to run activation-trace Hebbian stage: {error}"
                )));
            }
        }
    }

    match apply_runtime_reality_check(conn) {
        Ok(reality_report) => {
            result["reality_checked"] = reality_report
                .get("checked")
                .cloned()
                .unwrap_or_else(|| json!(0));
            result["reality_failed"] = reality_report
                .get("failed")
                .cloned()
                .unwrap_or_else(|| json!(0));
            result["reality_check"] = reality_report;
        }
        Err(error) => {
            if let Some(errors) = result["errors"].as_array_mut() {
                errors.push(json!(format!("Reality check failed: {error}")));
            }
        }
    }

    let runtime_truth = build_runtime_truth_payload(
        db_path,
        rust_writer,
        result
            .as_object()
            .context("runtime result must be object")?,
    );
    result["runtime_truth"] = runtime_truth;
    Ok(result)
}

enum RuntimePromotionOutcome {
    Promoted,
    Merged,
    Skipped,
}

