pub fn execute_batch_write(args: &BatchWriteArgs) -> anyhow::Result<BatchWriteReport> {
    let project = resolve_project_id(Some(args.project()));
    let db_path = args
        .db_path()
        .map(Path::to_path_buf)
        .unwrap_or_else(|| project_db_path(&project));
    if !db_path.exists() {
        bail!("database not found at {}", db_path.display());
    }

    match args.command() {
        BatchWriteCommand::AddMemory(inner) => execute_batch_add_memory(&project, &db_path, inner),
        BatchWriteCommand::MarkSuperseded(inner) => {
            let conn = Connection::open(&db_path).with_context(|| {
                format!(
                    "opening database for batch mark-superseded: {}",
                    db_path.display()
                )
            })?;
            mark_superseded(&conn, inner.old_id(), inner.new_id(), inner.reason()).with_context(
                || {
                    format!(
                        "marking {} superseded by {}",
                        inner.old_id(),
                        inner.new_id()
                    )
                },
            )?;
            Ok(batch_report("saved", "mark_superseded", &project, &db_path)
                .with_note_id(inner.old_id().to_string())
                .with_affected_rows(1))
        }
        BatchWriteCommand::UpsertRelation(inner) => {
            let conn = Connection::open(&db_path).with_context(|| {
                format!(
                    "opening database for batch upsert-relation: {}",
                    db_path.display()
                )
            })?;
            let (action, strength) = match inner.mode() {
                BatchRelationMode::Max => upsert_note_relation_max(
                    &conn,
                    inner.source_id(),
                    inner.target_id(),
                    inner.relation_type(),
                    inner.strength(),
                )?,
                BatchRelationMode::Strengthen => strengthen_note_relation(
                    &conn,
                    inner.source_id(),
                    inner.target_id(),
                    inner.relation_type(),
                    inner.strength(),
                    inner.delta(),
                )?,
            };
            Ok(batch_report("saved", "upsert_relation", &project, &db_path)
                .with_action(action)
                .with_strength(strength)
                .with_affected_rows(1))
        }
        BatchWriteCommand::NoteEvent(inner) => {
            let conn = Connection::open(&db_path).with_context(|| {
                format!(
                    "opening database for batch note-event: {}",
                    db_path.display()
                )
            })?;
            if let Some(payload) = inner.payload_json() {
                serde_json::from_str::<Value>(payload)
                    .with_context(|| "payload-json must be valid JSON")?;
            }
            insert_note_event(
                &conn,
                inner.note_id(),
                inner.event_type(),
                inner.related_note_id(),
                inner.payload_json(),
            )?;
            Ok(batch_report("saved", "note_event", &project, &db_path)
                .with_note_id(inner.note_id().to_string())
                .with_affected_rows(1))
        }
        BatchWriteCommand::StampLineage(inner) => {
            let conn = Connection::open(&db_path).with_context(|| {
                format!(
                    "opening database for batch stamp-lineage: {}",
                    db_path.display()
                )
            })?;
            let affected = stamp_note_lineage(
                &conn,
                inner.note_id(),
                inner.root_id(),
                inner.version(),
                inner.topic_key(),
            )?;
            Ok(batch_report("saved", "stamp_lineage", &project, &db_path)
                .with_note_id(inner.note_id().to_string())
                .with_affected_rows(affected))
        }
        BatchWriteCommand::UpdateNote(inner) => {
            let conn = Connection::open(&db_path).with_context(|| {
                format!(
                    "opening database for batch update-note: {}",
                    db_path.display()
                )
            })?;
            if let Some(metadata_json) = inner.metadata_json() {
                let value: Value = serde_json::from_str(metadata_json)
                    .with_context(|| "metadata-json must be valid JSON")?;
                if !value.is_object() {
                    bail!("metadata-json must be a JSON object");
                }
            }
            let affected = conn.execute(
                "UPDATE notes
                 SET metadata_json = COALESCE(?2, metadata_json),
                     confidence = COALESCE(?3, confidence),
                     evolution_state = COALESCE(?4, evolution_state)
                 WHERE id = ?1",
                params![
                    inner.note_id(),
                    inner.metadata_json(),
                    inner.confidence(),
                    inner.evolution_state()
                ],
            )?;
            Ok(batch_report("saved", "update_note", &project, &db_path)
                .with_note_id(inner.note_id().to_string())
                .with_affected_rows(affected))
        }
        BatchWriteCommand::ReportOutcome(inner) => {
            execute_batch_report_outcome(&project, &db_path, inner)
        }
        BatchWriteCommand::IncrementContradictCount(inner) => {
            let conn = Connection::open(&db_path).with_context(|| {
                format!(
                    "opening database for batch increment-contradict-count: {}",
                    db_path.display()
                )
            })?;
            let affected = conn.execute(
                "UPDATE notes
                 SET contradict_count = COALESCE(contradict_count, 0) + 1
                 WHERE id = ?1",
                params![inner.note_id()],
            )?;
            Ok(
                batch_report("saved", "increment_contradict_count", &project, &db_path)
                    .with_note_id(inner.note_id().to_string())
                    .with_affected_rows(affected),
            )
        }
        BatchWriteCommand::DreamInsertCandidate(inner) => {
            let conn = open_dream_batch_conn(&db_path, "dream-insert-candidate")?;
            let affected = insert_dream_candidate(&conn, &project, inner)?;
            Ok(
                batch_report("saved", "dream_insert_candidate", &project, &db_path)
                    .with_note_id(inner.id().to_string())
                    .with_affected_rows(affected),
            )
        }
        BatchWriteCommand::DreamUpdateCandidate(inner) => {
            let conn = open_dream_batch_conn(&db_path, "dream-update-candidate")?;
            let affected = update_dream_candidate(&conn, inner)?;
            Ok(
                batch_report("saved", "dream_update_candidate", &project, &db_path)
                    .with_note_id(inner.candidate_id().to_string())
                    .with_affected_rows(affected),
            )
        }
        BatchWriteCommand::DreamEvolutionLog(inner) => {
            let conn = open_dream_batch_conn(&db_path, "dream-evolution-log")?;
            let affected = insert_dream_evolution_log(&conn, &project, inner)?;
            Ok(
                batch_report("saved", "dream_evolution_log", &project, &db_path)
                    .with_note_id(inner.id().to_string())
                    .with_affected_rows(affected),
            )
        }
    }
}

