fn print_json_or_text<T: Serialize>(value: &T, as_json: bool) {
    if as_json {
        println!(
            "{}",
            serde_json::to_string_pretty(value).unwrap_or_else(|_| "{}".to_string())
        );
        return;
    }

    let rendered = serde_json::to_value(value).unwrap_or_else(|_| json!({}));
    println!(
        "{}",
        serde_json::to_string_pretty(&rendered).unwrap_or_else(|_| "{}".to_string())
    );
}

fn render_pulse(report: &DoctorReport) -> String {
    let mut lines = Vec::new();
    lines.push(format!("Memra Pulse - {}", report.project));
    lines.push(format!(
        "Runtime: {} | selected={} ({}) | live={} | rust={} {}",
        report.runtime_drift.status,
        report.selected_backend,
        report.selected_source,
        report.live_mcp_backend,
        report.rust_binary.version,
        report
            .rust_binary
            .build_commit
            .as_deref()
            .unwrap_or("unknown")
    ));
    lines.push(format!(
        "Storage: db={} | notes={} active={} | cold={} files/{} records",
        if report.db_exists {
            "present"
        } else {
            "missing"
        },
        report.note_count,
        report
            .stats
            .as_ref()
            .map(|stats| stats.active_notes)
            .unwrap_or(0),
        report
            .stats
            .as_ref()
            .map(|stats| stats.cold_storage_files)
            .unwrap_or(0),
        report
            .stats
            .as_ref()
            .map(|stats| stats.cold_storage_records)
            .unwrap_or(0)
    ));
    lines.push(format!(
        "Background: unread_hook_errors={} incomplete_writes={}",
        report.unread_hook_errors, report.unread_incomplete_writes
    ));
    lines.push(format!(
        "Batch lanes: total={} allowed={} keep_python={} must_migrate={} retire={}",
        report.batch_lanes.total,
        report.batch_lanes.allowed_batch,
        report.batch_lanes.keep_python_batch,
        report.batch_lanes.must_migrate,
        report.batch_lanes.retire
    ));

    if let Some(stats) = report.stats.as_ref() {
        if let Some(last_7d) = stats.last_7d.as_ref() {
            lines.push(format!(
                "Last 7d: queries={} recalls={}",
                last_7d.query_log_count, last_7d.recall_log_count
            ));
        }
        if let Some(trend) = stats.bench_trend.as_ref() {
            lines.push(format!(
                "Bench 7d: top1_mean_avg={} runs={} latest_top1={} latest_p95_ms={}",
                format_optional_f64(trend.bench_top1_mean_7d_avg, 2),
                trend.summary_count_7d,
                format_optional_f64(trend.latest_top1_mean, 2),
                format_optional_f64(trend.latest_latency_p95_ms, 2)
            ));
        }
        if let Some(top_recalls) = stats.top_recalls.as_ref() {
            if let Some(top) = top_recalls.first() {
                lines.push(format!(
                    "Top recall: {} x{} ({})",
                    top.note_id,
                    top.recall_count,
                    top.content_preview.as_deref().unwrap_or("no preview")
                ));
            }
        }
        if let Some(continuity) = stats.continuity.as_ref() {
            lines.push(format!(
                "Continuity: recall_age={} cross_agent={} project_scope={} activation_paths={} dream_hit={} broken_chains={}",
                continuity
                    .latest_recall_age_seconds
                    .map(|value| format!("{value}s"))
                    .unwrap_or_else(|| "n/a".to_string()),
                continuity.cross_agent_smoke_status,
                continuity.project_isolation_status,
                continuity.activation_path_count,
                continuity.dream_evidence_hit,
                continuity.unresolved_broken_chain_count
            ));
        }
        lines.push(format!(
            "Dream: total={} pending={} promoted={} held={} precision={} feedback_due={} applied={}",
            stats.dream.candidates_total,
            stats.dream.pending,
            stats.dream.promoted,
            stats.dream.held,
            stats
                .dream
                .latest_precision_rate
                .map(|value| format!("{value:.2}"))
                .unwrap_or_else(|| "n/a".to_string()),
            stats.dream.feedback.due,
            stats.dream.feedback.applied
        ));
        lines.push(format!(
            "Review queues: pending={} meta_fact={} top_sim={} replay_drift={} top_conf={} dream_feedback={}",
            stats.review_queues.total_pending,
            stats.review_queues.meta_fact_pending,
            stats
                .review_queues
                .meta_fact_top_similarity
                .map(|value| format!("{value:.2}"))
                .unwrap_or_else(|| "n/a".to_string()),
            stats.review_queues.replay_drift_pending,
            stats
                .review_queues
                .replay_drift_top_confidence
                .map(|value| format!("{value:.2}"))
                .unwrap_or_else(|| "n/a".to_string()),
            stats.review_queues.dream_feedback_due
        ));
        if let Some(activation) = stats.activation.as_ref() {
            lines.push(format!(
                "Activation: traces={} 7d={} zero_rate={} dream_hit={} latency_p50/p95={}/{}ms",
                activation.trace_log_count,
                activation.traces_last_7d,
                format_rate(activation.zero_activation_query_rate),
                format_rate(activation.dream_evidence_hit_rate),
                activation
                    .latency_p50_ms
                    .map(|value| value.to_string())
                    .unwrap_or_else(|| "n/a".to_string()),
                activation
                    .latency_p95_ms
                    .map(|value| value.to_string())
                    .unwrap_or_else(|| "n/a".to_string())
            ));
            if !activation.depth_distribution.is_empty() {
                lines.push(format!(
                    "Activation depth: {}",
                    activation
                        .depth_distribution
                        .iter()
                        .map(|(depth, count)| format!("d{depth}={count}"))
                        .collect::<Vec<_>>()
                        .join(", ")
                ));
            }
            if let Some(path) = activation.top_activation_paths.first() {
                lines.push(format!(
                    "Top path: {} [{}] x{}",
                    path.path.join(" -> "),
                    path.relation_type,
                    path.count
                ));
            }
            if let Some(trace) = activation.latest_trace.as_ref() {
                lines.push(format!(
                    "Latest trace: {} depth={} activated={} query=\"{}\"",
                    trace.tool,
                    trace.activation_max_depth,
                    trace.activation_result_count,
                    pulse_truncate_chars(&trace.query, 60)
                ));
            }
            lines.push(format!(
                "Activation budget: unresolved={} recovered={} unexpected_zero={} expected_zero={} top_fail={}",
                activation.quality_budget.unresolved_failure_count,
                activation.quality_budget.recovered_failure_count,
                activation.quality_budget.unexpected_zero_activation_count,
                activation.quality_budget.expected_zero_activation_count,
                activation
                    .quality_budget
                    .top_failing_class
                    .as_deref()
                    .unwrap_or("none")
            ));
        }
        let mut attention = Vec::new();
        if report.runtime_drift.status == "blocked" {
            attention.push("runtime drift blocked".to_string());
        }
        if report.unread_hook_errors > 0 {
            attention.push(format!("{} hook errors unread", report.unread_hook_errors));
        }
        if report.unread_incomplete_writes > 0 {
            attention.push(format!(
                "{} incomplete writes unread",
                report.unread_incomplete_writes
            ));
        }
        if stats.dream.pending > 0 {
            attention.push(format!("{} pending dreams", stats.dream.pending));
        }
        if stats.dream.feedback.due > 0 {
            attention.push(format!(
                "{} dream feedback due (run: ma stats --project {} --full --json)",
                stats.dream.feedback.due, report.project
            ));
        }
        if stats.review_queues.total_pending > 0 {
            attention.push(format!(
                "{} review candidates (run: ma review-queue --project {} --limit 10)",
                stats.review_queues.total_pending, report.project
            ));
        }
        if let Some(continuity) = stats.continuity.as_ref() {
            if continuity.cross_agent_smoke_status != "pass_recent" {
                attention.push(format!(
                    "cross-agent continuity smoke {} (run: ma stats --project {} --full --json)",
                    continuity.cross_agent_smoke_status, report.project
                ));
            }
            if continuity.project_isolation_status != "pass" {
                attention.push("project isolation continuity check unknown".to_string());
            }
            if continuity.unresolved_broken_chain_count > 0 {
                attention.push(format!(
                    "{} unresolved broken activation chain(s)",
                    continuity.unresolved_broken_chain_count
                ));
            }
        }
        if report.batch_lanes.must_migrate > 0 {
            attention.push(format!(
                "{} Python batch lanes need migration",
                report.batch_lanes.must_migrate
            ));
        }
        if let Some(activation) = stats.activation.as_ref() {
            if let Some(class_name) = activation.quality_budget.top_failing_class.as_deref() {
                attention.push(format!(
                    "activation budget fail {} query=\"{}\" (run: ma stats --project {} --full --json)",
                    class_name,
                    pulse_truncate_chars(
                        activation
                            .quality_budget
                            .top_failing_query
                            .as_deref()
                            .unwrap_or("unknown"),
                        48
                    ),
                    report.project
                ));
            } else if activation.zero_activation_query_rate >= 0.5 && activation.trace_log_count > 0
            {
                attention.push(format!(
                    "zero activation mostly expected {}",
                    format_rate(activation.zero_activation_query_rate)
                ));
            }
        }
        lines.push(format!(
            "Needs attention: {}",
            if attention.is_empty() {
                "none".to_string()
            } else {
                attention.join("; ")
            }
        ));
    } else {
        lines.push("Stats: unavailable (database missing or --full collection failed)".to_string());
    }

    lines.truncate(40);
    lines.join("\n") + "\n"
}

fn render_review_queue(report: &ReviewQueueReport) -> String {
    let mut lines = Vec::new();
    lines.push(format!(
        "Memra Review Queue - {} | source={} | pending={}",
        report.project,
        report.source,
        review_queue_pending_for_source(&report.summary, &report.source)
    ));
    lines.push(format!(
        "Summary: meta_fact={} top_sim={} replay_drift={} top_conf={} dream_feedback={}",
        report.summary.meta_fact_pending,
        format_optional_f64(report.summary.meta_fact_top_similarity, 2),
        report.summary.replay_drift_pending,
        format_optional_f64(report.summary.replay_drift_top_confidence, 2),
        report.summary.dream_feedback_due
    ));

    if report.items.is_empty() {
        lines.push("No pending review candidates.".to_string());
        return lines.join("\n") + "\n";
    }

    let max_items_for_glance = ((40usize.saturating_sub(lines.len() + 1)) / 5).max(1);
    let shown_count = report.items.len().min(max_items_for_glance);
    lines.push(format!(
        "Top {} of {} candidates:",
        shown_count,
        report.items.len()
    ));
    for (idx, item) in report.items.iter().take(shown_count).enumerate() {
        let primary = item.primary_id.as_deref().unwrap_or("-");
        let secondary = item.secondary_id.as_deref().unwrap_or("-");
        lines.push(format!(
            "{}. {} {} {}={:.3} age={} at={}",
            idx + 1,
            item.queue,
            pulse_truncate_chars(&item.id, 12),
            item.score_label,
            item.score,
            format_review_age(item.age_hours),
            item.detected_at.as_deref().unwrap_or("-")
        ));
        lines.push(format!(
            "   ids: {} -> {}",
            pulse_truncate_chars(primary, 12),
            pulse_truncate_chars(secondary, 12)
        ));
        lines.push(format!("   {}", pulse_truncate_chars(&item.summary, 110)));
        lines.push(format!(
            "   next: {}",
            pulse_truncate_chars(&item.recommended_action, 110)
        ));
        lines.push(format!(
            "   cmd: {}",
            pulse_truncate_chars(&item.recommended_command, 110)
        ));
    }
    lines.truncate(40);
    lines.join("\n") + "\n"
}

fn review_queue_pending_for_source(summary: &ReviewQueueStats, source: &str) -> i64 {
    match source {
        "meta-fact" => summary.meta_fact_pending,
        "replay-drift" => summary.replay_drift_pending,
        "dream-feedback" => summary.dream_feedback_due,
        _ => summary.total_pending,
    }
}

fn format_rate(value: f64) -> String {
    format!("{:.0}%", value * 100.0)
}

fn format_optional_f64(value: Option<f64>, decimals: usize) -> String {
    value
        .map(|number| format!("{number:.decimals$}"))
        .unwrap_or_else(|| "n/a".to_string())
}

fn pulse_truncate_chars(value: &str, max_chars: usize) -> String {
    let normalized = value.replace(['\r', '\n'], " ");
    let mut out = normalized.chars().take(max_chars).collect::<String>();
    if normalized.chars().count() > max_chars {
        out.push_str("...");
    }
    out
}

fn print_init_summary(report: &InitReport) {
    println!("Initialized project {}", report.project);
    println!("  DB: {}", report.db_path);
    println!("  Constitution: {}", report.constitution_path);
    if report.dry_run {
        println!("  Mode: dry-run");
    }
    println!("  MCP config targets:");
    for target in &report.config_targets {
        println!("    - {target}");
    }
}

fn print_demo_summary(report: &DemoReport) {
    println!("Seeded demo project {}", report.project);
    println!("  DB: {}", report.db_path);
    println!("  Seeded notes: {}", report.seeded_notes);
    println!("  Duplicates skipped: {}", report.duplicates);
    println!("  Warnings: {}", report.warnings);
}

fn print_recover_summary(report: &RecoverReport) {
    if report.dry_run {
        println!("Recover dry-run for project {}", report.project);
    } else {
        println!("Recovered project {}", report.project);
    }
    println!("  DB: {}", report.db_path);
    println!("  Cold-storage files: {}", report.cold_storage_files);
    println!("  Records discovered: {}", report.records_discovered);
    println!("  Records restored: {}", report.records_restored);
    println!("  Embeddings missing: {}", report.embeddings_missing);
    if let Some(ref backup) = report.backup_path {
        println!("  Previous DB backup: {backup}");
    }
}

#[derive(Debug, Clone)]
struct WikiNote {
    id: String,
    content: String,
    category: Option<String>,
    confidence: Option<f64>,
    created_at: Option<String>,
    updated_at: Option<String>,
    metadata_json: Option<String>,
    root_id: Option<String>,
    version: Option<i64>,
    topic_key: Option<String>,
    evolution_state: Option<String>,
    is_head: bool,
    is_active: bool,
}

