    static DREAM_AUTO_PROMOTE_ENV_LOCK: Mutex<()> = Mutex::new(());

    fn with_dream_auto_promote_env<T>(value: Option<&str>, run: impl FnOnce() -> T) -> T {
        let _guard = DREAM_AUTO_PROMOTE_ENV_LOCK
            .lock()
            .expect("env lock poisoned");
        let old = env::var("MA_DREAM_AUTO_PROMOTE").ok();
        match value {
            Some(value) => unsafe {
                env::set_var("MA_DREAM_AUTO_PROMOTE", value);
            },
            None => unsafe {
                env::remove_var("MA_DREAM_AUTO_PROMOTE");
            },
        }
        let result = std::panic::catch_unwind(std::panic::AssertUnwindSafe(run));
        match old {
            Some(value) => unsafe {
                env::set_var("MA_DREAM_AUTO_PROMOTE", value);
            },
            None => unsafe {
                env::remove_var("MA_DREAM_AUTO_PROMOTE");
            },
        }
        match result {
            Ok(value) => value,
            Err(payload) => std::panic::resume_unwind(payload),
        }
    }

    fn temp_dir(name: &str) -> Result<PathBuf, String> {
        let now = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .map_err(|error| error.to_string())?
            .as_nanos();
        let dir = std::env::temp_dir().join(format!("ma-phase4-test-{now}-{name}"));
        fs::create_dir_all(&dir).map_err(|error| error.to_string())?;
        Ok(dir)
    }

    #[test]
    fn cli_daemon_socket_path_is_project_scoped() -> Result<(), String> {
        let home = temp_dir("cli-daemon-socket")?;
        let path = cli_daemon_socket_path_at(&home, "Memra!");
        assert_eq!(path, home.join("run").join("memra.sock"));

        let fallback = cli_daemon_socket_path_at(&home, "DemoERP");
        assert_eq!(fallback, home.join("run").join("demoerp.sock"));
        Ok(())
    }

    #[test]
    fn cli_forward_search_request_preserves_search_flags() -> Result<(), String> {
        let parsed = Cli::try_parse_from([
            "ma",
            "search",
            "release workflow",
            "--project",
            "alpha",
            "--limit",
            "3",
            "--mode",
            "lexical",
            "--min-score",
            "0.6",
            "--include-constitution",
        ])
        .map_err(|error| error.to_string())?;
        let args = match parsed.into_command() {
            Command::Search(args) => args,
            other => return Err(format!("expected search command, got {other:?}")),
        };

        let request = cli_forward_search_request(&args, "alpha".to_string());
        assert_eq!(request.command, "search");
        assert_eq!(request.project, "alpha");
        assert_eq!(request.query, "release workflow");
        assert_eq!(request.limit, 3);
        assert_eq!(request.search_mode.as_deref(), Some("lexical"));
        assert_eq!(request.min_score, 0.6);
        assert!(request.include_constitution);
        Ok(())
    }

