    #[test]
    fn markdown_ingest_chunks_use_frontmatter_and_headings() {
        let raw = "---\ntitle: Root Facts\n---\n# Contract first\nKeep project contracts canonical.\n\n## Rust path\nUse Rust storage and FTS5.\n";
        let chunks = markdown_ingest_chunks(Path::new("docs/PROJECT_FACTS.md"), raw, 17, 91);

        assert_eq!(chunks.len(), 2);
        assert_eq!(chunks[0].title, "Contract first");
        assert_eq!(chunks[1].title, "Rust path");
        assert_eq!(chunks[0].mtime_seconds, 17);
        assert_eq!(chunks[0].byte_len, 91);
        assert!(chunks[0].content.contains("[FACT] Static doc ingest"));
        assert!(chunks[0].content.contains("Source: docs/PROJECT_FACTS.md"));
        assert!(chunks[1].content.contains("Use Rust storage and FTS5"));
    }

