    fn write_jsonl_exchange(path: &Path, user: &str, assistant: &str) -> Result<(), String> {
        fs::write(
            path,
            [
                json!({"role": "user", "content": user}).to_string(),
                json!({"role": "assistant", "content": assistant}).to_string(),
            ]
            .join("\n"),
        )
        .map_err(|error| error.to_string())
    }

