    #[test]
    fn mine_convos_import_writes_via_rust_writer_with_room_and_classification() -> Result<(), String>
    {
        let dir = temp_dir("mine-convos-import")?;
        let file = dir.join("session.jsonl");
        write_jsonl_exchange(
            &file,
            "Project decision: import conversations through Rust.",
            "Use the WriteOrchestrator path, preserve the requested room, and classify the imported exchange.",
        )?;
        let db_path = dir.join("memory_anchor.sqlite3");
        let db_arg = db_path.to_string_lossy().to_string();
        let file_arg = file.to_string_lossy().to_string();

        let parsed = Cli::try_parse_from([
            "ma",
            "mine-convos",
            file_arg.as_str(),
            "--project",
            "alpha",
            "--room",
            "ops",
            "--db",
            db_arg.as_str(),
        ])
        .map_err(|error| error.to_string())?;
        let Command::MineConvos(args) = parsed.into_command() else {
            return Err("expected mine-convos command".to_string());
        };
        let collected = collect_mine_convos(&file, 500).map_err(|error| error.to_string())?;
        let report =
            import_mine_convos_for_cli(&args, &collected).map_err(|error| error.to_string())?;

        assert_eq!(report.project, "alpha");
        assert_eq!(report.room.as_deref(), Some("ops"));
        assert_eq!(report.total_exchanges, 1);
        assert_eq!(report.written, 1);
        assert_eq!(report.duplicates, 0);
        assert_eq!(report.errors, 0);

        let conn = Connection::open(&db_path).map_err(|error| error.to_string())?;
        let (content, layer, category, room, source, project): (
            String,
            String,
            Option<String>,
            Option<String>,
            Option<String>,
            Option<String>,
        ) = conn
            .query_row(
                "SELECT content, layer, category, room, source, project_id FROM notes",
                [],
                |row| {
                    Ok((
                        row.get(0)?,
                        row.get(1)?,
                        row.get(2)?,
                        row.get(3)?,
                        row.get(4)?,
                        row.get(5)?,
                    ))
                },
            )
            .map_err(|error| error.to_string())?;

        assert!(content.contains("Q: Project decision"));
        assert!(content.contains("A: Use the WriteOrchestrator path"));
        assert_eq!(layer, "verified_fact");
        assert_eq!(category.as_deref(), Some("event"));
        assert_eq!(room.as_deref(), Some("ops"));
        assert_eq!(source.as_deref(), Some("convo_miner"));
        assert_eq!(project.as_deref(), Some("alpha"));
        Ok(())
    }

    #[test]
    fn mine_convos_import_skips_short_chunks_and_truncates_long_assistant_text() {
        let short = Exchange {
            user_text: "tiny".to_string(),
            assistant_text: "ok".to_string(),
            timestamp: None,
        };
        assert!(mine_convos_memory_content(&short).len() < 20);

        let cjk_short = Exchange {
            user_text: "短短短".to_string(),
            assistant_text: "短答".to_string(),
            timestamp: None,
        };
        let cjk_content = mine_convos_memory_content(&cjk_short);
        assert!(cjk_content.len() >= 20);
        assert!(cjk_content.chars().count() < 20);

        let long = Exchange {
            user_text: "Question with enough context".to_string(),
            assistant_text: "x".repeat(510),
            timestamp: None,
        };
        let content = mine_convos_memory_content(&long);
        assert!(content.contains("Q: Question with enough context"));
        let assistant = content
            .lines()
            .find_map(|line| line.strip_prefix("A: "))
            .expect("assistant line");
        assert_eq!(assistant.chars().count(), 500);
        assert!(assistant.ends_with("..."));
    }

