    #[test]
    fn compact_context_snapshot_respects_token_budget() {
        let full = json!({
            "mode": "full",
            "project_id": "alpha",
            "summary": "active work summary ".repeat(20),
            "active_checkpoints": [
                {"task_id": "t1", "summary": "finish compact context"}
            ],
            "recent_memories": [
                {"id": "n1", "preview": "recent memory"}
            ],
        });

        let compact = compact_context_snapshot(full, 100);
        assert_eq!(compact["mode"], json!("compact"));
        assert_eq!(compact["source_mode"], json!("full"));
        assert_eq!(compact["token_budget"], json!(100));
        assert_eq!(compact["char_budget"], json!(400));
        assert!(compact["sections"].as_array().unwrap().len() >= 2);
        assert!(
            compact["compact_text"]
                .as_str()
                .unwrap()
                .contains("## summary")
        );
        assert!(
            compact["compact_text"].as_str().unwrap().chars().count()
                <= compact["char_budget"].as_u64().unwrap() as usize + 3
        );
    }

    #[test]
    fn checkpoint_cli_saves_and_upserts_rust_checkpoint() -> Result<(), String> {
        let dir = temp_dir("checkpoint-cli")?;
        let db_path = dir.join("memory_anchor.sqlite3");
        let db_arg = db_path.to_string_lossy().to_string();

        let parsed = Cli::try_parse_from([
            "ma",
            "checkpoint",
            "task-1",
            "first state",
            "--project",
            "alpha",
            "--status",
            "blocked",
            "--next-step",
            "continue",
            "--blocker",
            "waiting",
            "--json",
            "--db",
            db_arg.as_str(),
        ])
        .map_err(|error| error.to_string())?;
        let Command::Checkpoint(first_args) = parsed.into_command() else {
            return Err("expected checkpoint command".to_string());
        };
        let first = save_checkpoint_for_cli(&first_args).map_err(|error| error.to_string())?;
        assert_eq!(first.status, "saved");
        assert_eq!(first.project, "alpha");
        assert!(first.text.contains("断点已保存"));

        let parsed = Cli::try_parse_from([
            "ma",
            "checkpoint",
            "task-1",
            "second state",
            "--project",
            "alpha",
            "--status",
            "completed",
            "--json",
            "--db",
            db_arg.as_str(),
        ])
        .map_err(|error| error.to_string())?;
        let Command::Checkpoint(second_args) = parsed.into_command() else {
            return Err("expected checkpoint command".to_string());
        };
        let second = save_checkpoint_for_cli(&second_args).map_err(|error| error.to_string())?;
        assert_eq!(second.status, "saved");

        let conn = Connection::open(&db_path).map_err(|error| error.to_string())?;
        let rows = conn
            .prepare(
                "SELECT content, metadata_json FROM notes
                 WHERE is_active = 1
                   AND project_id = 'alpha'
                   AND json_valid(metadata_json)
                   AND json_extract(metadata_json, '$.record_type') = 'checkpoint'
                   AND json_extract(metadata_json, '$.task_id') = 'task-1'",
            )
            .map_err(|error| error.to_string())?
            .query_map([], |row| {
                Ok((row.get::<_, String>(0)?, row.get::<_, String>(1)?))
            })
            .map_err(|error| error.to_string())?
            .collect::<Result<Vec<_>, _>>()
            .map_err(|error| error.to_string())?;
        assert_eq!(rows.len(), 1);
        assert!(rows[0].0.contains("second state"));
        let metadata: Value =
            serde_json::from_str(&rows[0].1).map_err(|error| error.to_string())?;
        assert_eq!(metadata["task_status"], json!("completed"));
        assert_eq!(metadata["record_type"], json!("checkpoint"));
        Ok(())
    }

