    #[test]
    fn add_cli_json_writes_via_rust_writer() -> Result<(), String> {
        let dir = temp_dir("add-cli")?;
        let db_path = dir.join("memory_anchor.sqlite3");
        let db_arg = db_path.to_string_lossy().to_string();

        let parsed = Cli::try_parse_from([
            "ma",
            "add",
            "Project decision: Rust CLI add writes through WriteOrchestrator.",
            "--project",
            "alpha",
            "--category",
            "decision",
            "--layer",
            "fact",
            "--confidence",
            "0.8",
            "--json",
            "--db",
            db_arg.as_str(),
        ])
        .map_err(|error| error.to_string())?;
        let Command::Add(args) = parsed.into_command() else {
            return Err("expected add command".to_string());
        };
        let report = add_for_cli(&args).map_err(|error| error.to_string())?;

        assert_eq!(report["status"], json!("saved"));
        assert_eq!(report["layer"], json!("verified_fact"));
        assert_eq!(report["confidence"], json!(0.8));
        assert_eq!(report["project"], json!("alpha"));

        let id = report["id"]
            .as_str()
            .ok_or_else(|| "expected saved id".to_string())?;
        let conn = Connection::open(&db_path).map_err(|error| error.to_string())?;
        let row = conn
            .query_row(
                "SELECT layer, category, confidence, source, agent, project_id
                 FROM notes WHERE id = ?1",
                params![id],
                |row| {
                    Ok((
                        row.get::<_, String>(0)?,
                        row.get::<_, Option<String>>(1)?,
                        row.get::<_, Option<f64>>(2)?,
                        row.get::<_, Option<String>>(3)?,
                        row.get::<_, Option<String>>(4)?,
                        row.get::<_, Option<String>>(5)?,
                    ))
                },
            )
            .map_err(|error| error.to_string())?;
        assert_eq!(row.0, "verified_fact");
        assert_eq!(row.1.as_deref(), Some("decision"));
        assert_eq!(row.2, Some(0.8));
        assert_eq!(row.3.as_deref(), Some("user"));
        assert_eq!(row.4.as_deref(), Some("cli"));
        assert_eq!(row.5.as_deref(), Some("alpha"));
        Ok(())
    }

