    #[test]
    fn feedback_due_cli_json_surfaces_review_action_and_dream_queues() -> Result<(), String> {
        let dir = temp_dir("feedback-due-cli")?;
        let db_path = dir.join("memory_anchor.sqlite3");
        let db_arg = db_path.to_string_lossy().to_string();

        let parsed = Cli::try_parse_from([
            "ma",
            "feedback-due",
            "--project",
            "alpha",
            "--limit",
            "5",
            "--json",
            "--db",
            db_arg.as_str(),
        ])
        .map_err(|error| error.to_string())?;
        let Command::FeedbackDue(args) = parsed.into_command() else {
            return Err("expected feedback-due command".to_string());
        };
        let empty = feedback_due_for_cli(&args).map_err(|error| error.to_string())?;
        assert_eq!(empty["project_id"], json!("alpha"));
        assert_eq!(empty["counts"]["review_required"], json!(0));

        let now = Utc::now().to_rfc3339();
        let conn = Connection::open(&db_path).map_err(|error| error.to_string())?;
        conn.execute(
            "INSERT INTO notes (id, content, layer, project_id, is_active, metadata_json)
             VALUES
             ('mem-due', 'Dream feedback due', 'verified_fact', 'alpha', 1, '{}'),
             ('mem-confirmed', 'Dream already confirmed', 'verified_fact', 'alpha', 1, '{\"success_count\":1}'),
             ('mem-beta', 'Other project dream', 'verified_fact', 'beta', 1, '{}')",
            [],
        )
        .map_err(|error| error.to_string())?;
        conn.execute(
            "INSERT INTO experience_records (
                id, title, summary, kind, status, origin, project_id,
                source_note_id, topic_key, confidence, evidence_note_ids_json,
                metadata_json, superseded_by, created_at, updated_at
             )
             VALUES
             ('exp-review', 'Review required', 'needs review', 'heuristic', 'review_required',
              'test', 'alpha', NULL, 'feedback-due', 0.50, '[]',
              '{\"expert_deliberation\":{\"next_actions\":[\"inspect evidence\"]}}', NULL, ?1, ?1),
             ('exp-action', 'Action source', 'turn this into a playbook', 'procedure', 'stable',
              'test', 'alpha', 'procedure-note', 'feedback-due-action', 0.90, '[\"fallback-note\"]',
              '{}', NULL, ?1, ?1),
             ('exp-beta', 'Beta review', 'wrong project', 'heuristic', 'review_required',
              'test', 'beta', NULL, 'feedback-due', 0.50, '[]', '{}', NULL, ?1, ?1)",
            [&now],
        )
        .map_err(|error| error.to_string())?;
        conn.execute(
            "INSERT INTO experience_actions (
                id, experience_id, action_type, target_system, status, summary,
                payload_json, outcome_note_id, created_at, updated_at
             )
             VALUES
             ('act-1', 'exp-action', 'write_playbook', 'Hermes', 'recommended',
              'turn this into a playbook', '{}', NULL, ?1, ?1),
             ('act-done', 'exp-action', 'write_playbook', 'Hermes', 'completed',
              'already done', '{}', 'outcome-note', ?1, ?1)",
            [&now],
        )
        .map_err(|error| error.to_string())?;
        conn.execute(
            "INSERT INTO dream_candidates
             (id, project_id, source_type, summary, confidence, evidence_ids, verdict, promoted_to, created_at, promoted_at)
             VALUES
             ('dream-due', 'alpha', 'consolidation', 'needs feedback', 0.88, '[\"e1\"]', 'promoted', 'mem-due', ?1, ?1),
             ('dream-done', 'alpha', 'consolidation', 'already confirmed', 0.99, '[\"e2\"]', 'promoted', 'mem-confirmed', ?1, ?1),
             ('dream-beta', 'beta', 'consolidation', 'wrong project', 0.77, '[\"e3\"]', 'promoted', 'mem-beta', ?1, ?1)",
            [&now],
        )
        .map_err(|error| error.to_string())?;
        drop(conn);

        let report = feedback_due_for_cli(&args).map_err(|error| error.to_string())?;
        assert_eq!(report["project_id"], json!("alpha"));
        assert_eq!(report["counts"]["feedback_deficit"], json!(50));
        assert_eq!(report["counts"]["review_required"], json!(1));
        assert_eq!(report["counts"]["recommended_actions"], json!(1));
        assert_eq!(report["counts"]["dream_feedback_due"], json!(1));
        assert_eq!(report["returned_counts"]["review_required"], json!(1));
        assert_eq!(report["returned_counts"]["recommended_actions"], json!(1));
        assert_eq!(report["returned_counts"]["dream_feedback_due"], json!(1));
        assert_eq!(
            report["review_required"][0]["experience_id"],
            json!("exp-review")
        );
        assert_eq!(
            report["review_required"][0]["review_outcome"],
            json!("needs_review")
        );
        assert_eq!(
            report["review_required"][0]["next_actions"][0],
            json!("inspect evidence")
        );
        assert_eq!(
            report["recommended_actions"][0]["memory_id"],
            json!("procedure-note")
        );
        assert!(
            report["recommended_actions"][0]["suggested_tool"]
                .as_str()
                .unwrap_or_default()
                .contains("action_id=\"act-1\"")
        );
        assert_eq!(
            report["dream_feedback_due"][0]["memory_id"],
            json!("mem-due")
        );
        assert!(
            report["dream_feedback_due"][0]["suggested_tool"]
                .as_str()
                .unwrap_or_default()
                .contains("report_outcome")
        );
        Ok(())
    }

