    #[test]
    fn packet_cli_json_emits_full_schema_and_preserves_project_isolation() -> Result<(), String> {
        let dir = temp_dir("packet-cli")?;
        let db_path = dir.join("memory_anchor.sqlite3");
        bootstrap_database(&db_path).map_err(|error| error.to_string())?;
        let conn = Connection::open(&db_path).map_err(|error| error.to_string())?;
        let now = Utc::now().to_rfc3339();
        conn.execute(
            "INSERT INTO notes
             (id, content, layer, category, is_active, confidence, project_id, created_at, updated_at, metadata_json)
             VALUES
             ('pref-a', 'User prefers exact evidence.', 'identity_schema', NULL, 1, 0.91, 'alpha', ?1, ?1, NULL),
             ('decision-a', 'DECISION ONLY IN ALPHA packet', 'verified_fact', 'decision', 1, 0.94, 'alpha', ?1, ?1, NULL),
             ('decision-b', 'DECISION ONLY IN BETA packet', 'verified_fact', 'decision', 1, 0.95, 'beta', ?1, ?1, NULL),
             ('standard-a', 'Every claim needs local evidence.', 'verified_fact', 'evaluation', 1, 0.90, 'alpha', ?1, ?1, NULL),
             ('checkpoint-a', '[断点] packet-rust: finish packet alias', 'event_log', 'event', 1, 0.95, 'alpha', ?1, ?1,
                '{\"record_type\":\"checkpoint\",\"task_id\":\"packet-rust\",\"task_status\":\"blocked\",\"next_step\":\"run M1 CI\",\"blocker\":\"none\"}'),
             ('outcome-a', 'feedback recorded', 'event_log', 'event', 1, 0.95, 'alpha', ?1, ?1,
                '{\"record_type\":\"outcome\",\"memory_id\":\"decision-a\",\"outcome\":\"confirmed\",\"reason\":\"accepted\"}'),
             ('correction-a', '[CORRECTION] packet writeback should be reviewed', 'procedure_schema', 'bug', 1, 0.93, 'alpha', ?1, ?1, NULL)",
            [&now],
        )
        .map_err(|error| error.to_string())?;
        drop(conn);

        let db_arg = db_path.to_string_lossy().to_string();
        let parsed = Cli::try_parse_from([
            "ma",
            "packet",
            "--project",
            "alpha",
            "--db",
            db_arg.as_str(),
        ])
        .map_err(|error| error.to_string())?;
        let Command::Packet(args) = parsed.into_command() else {
            return Err("expected packet command".to_string());
        };
        let packet = packet_for_cli(&args).map_err(|error| error.to_string())?;

        assert_eq!(
            packet["schema"],
            json!("memory_anchor.project_memory_packet.v1")
        );
        assert!(packet.get("db_path").is_none());
        assert_eq!(packet["project_id"], json!("alpha"));
        assert_eq!(packet["freshness"]["stale"], json!(false));
        assert_eq!(packet["identity_and_preferences"][0]["id"], json!("pref-a"));
        assert_eq!(
            packet["durable_decisions"][0]["summary"],
            json!("DECISION ONLY IN ALPHA packet")
        );
        let durable = packet["durable_decisions"]
            .as_array()
            .ok_or_else(|| "expected durable decisions".to_string())?;
        assert!(
            durable
                .iter()
                .all(|item| item["summary"] != json!("DECISION ONLY IN BETA packet")),
            "beta decision leaked into alpha packet: {durable:?}"
        );
        assert_eq!(
            packet["active_checkpoints"][0]["task_id"],
            json!("packet-rust")
        );
        assert_eq!(
            packet["active_checkpoints"][0]["next_step"],
            json!("run M1 CI")
        );
        assert_eq!(packet["evaluation_standards"][0]["id"], json!("standard-a"));
        assert_eq!(packet["recent_outcomes"][0]["outcome"], json!("confirmed"));
        assert_eq!(
            packet["suggested_writeback"][0]["kind"],
            json!("correction")
        );
        assert!(
            ["macbook-air", "mac-mini", "macbook-pro"].contains(
                &packet["source_instance"]
                    .as_str()
                    .ok_or_else(|| "expected source_instance".to_string())?
            )
        );
        Ok(())
    }

