    #[test]
    fn grade_outcome_accepts_green_fixture_with_skip_d() -> Result<(), String> {
        let dir = temp_dir("grade")?;
        let logs_dir = dir.join("logs");
        let dogfood_dir = dir.join("dogfood");
        let evidence_dir = dogfood_dir.join("2026-05-15");
        fs::create_dir_all(&logs_dir).map_err(|error| error.to_string())?;
        fs::create_dir_all(&evidence_dir).map_err(|error| error.to_string())?;

        let phase9 = dir.join("phase9-dream.json");
        fs::write(
            &phase9,
            serde_json::to_string(&json!({
                "candidate_count": 2,
                "promoted_count": 1,
                "governance_bucket": "normal"
            }))
            .map_err(|error| error.to_string())?,
        )
        .map_err(|error| error.to_string())?;
        let phase10 = dir.join("phase10-dream_evolve.json");
        fs::write(
            &phase10,
            serde_json::to_string(&json!({
                "verdict_counts": {"confirmed": 3, "outdated": 0}
            }))
            .map_err(|error| error.to_string())?,
        )
        .map_err(|error| error.to_string())?;
        let orchestration = logs_dir.join("orchestration_20260515.json");
        fs::write(
            &orchestration,
            serde_json::to_string(&json!({
                "overall_status": "passed",
                "failed_stage_count": 0,
                "phase6_observability": {"ok": true},
                "stages": [
                    {"status": "passed", "duration_seconds": 20, "log_path": phase9.display().to_string()},
                    {"status": "skipped", "duration_seconds": 1, "log_path": phase10.display().to_string()}
                ]
            }))
            .map_err(|error| error.to_string())?,
        )
        .map_err(|error| error.to_string())?;

        let samples = (0..20)
            .map(|idx| Value::String(format!("[FACT] sample {idx}")))
            .collect::<Vec<_>>();
        let evidence = evidence_dir.join("evidence.json");
        fs::write(
            &evidence,
            serde_json::to_string(&json!({
                "sample_size": 20,
                "cohort": "reinterpretation",
                "samples": samples
            }))
            .map_err(|error| error.to_string())?,
        )
        .map_err(|error| error.to_string())?;

        let parsed = Cli::try_parse_from([
            "ma",
            "grade",
            "--skip-d",
            "--date",
            "2026-05-15",
            "--orchestration",
            orchestration
                .to_str()
                .ok_or("orchestration path was not UTF-8")?,
            "--dogfood-dir",
            dogfood_dir.to_str().ok_or("dogfood path was not UTF-8")?,
            "--pending-dir",
            dir.join("missing-pending")
                .to_str()
                .ok_or("pending path was not UTF-8")?,
        ])
        .map_err(|error| error.to_string())?;
        let Command::Grade(args) = parsed.into_command() else {
            return Err("expected grade command".to_string());
        };
        let report = grade_outcome(&args).map_err(|error| error.to_string())?;
        assert_eq!(report.result, "satisfied");
        assert!(report.failed_ids.is_empty());
        assert_eq!(report.criteria.len(), 18);
        assert_eq!(grade_exit_code(&report), 0);
        Ok(())
    }

