    fn init_strengthen_prune_schema(conn: &Connection) -> Result<(), String> {
        conn.execute_batch(
            "CREATE TABLE notes (
                id TEXT PRIMARY KEY,
                content TEXT,
                layer TEXT,
                confidence REAL,
                recall_count INTEGER DEFAULT 0,
                support_count INTEGER DEFAULT 0,
                metadata_json TEXT,
                is_active INTEGER DEFAULT 1,
                evolution_state TEXT DEFAULT 'active',
                created_at TEXT,
                updated_at TEXT,
                last_verified TEXT,
                root_id TEXT,
                topic_key TEXT,
                vector_json TEXT,
                source TEXT,
                confirmed_at INTEGER,
                version INTEGER DEFAULT 1,
                is_head INTEGER DEFAULT 1
            );
            CREATE TABLE note_relations (
                from_note_id TEXT NOT NULL,
                to_note_id TEXT NOT NULL,
                relation_type TEXT NOT NULL,
                strength REAL NOT NULL DEFAULT 0.5,
                created_at TEXT DEFAULT (datetime('now')),
                PRIMARY KEY (from_note_id, to_note_id, relation_type)
            );
            CREATE TABLE note_events (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                note_id TEXT NOT NULL,
                event_type TEXT NOT NULL,
                related_note_id TEXT,
                payload_json TEXT,
                created_at TEXT DEFAULT (datetime('now'))
            );
            CREATE TABLE query_log (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                timestamp TEXT,
                top_result_ids TEXT
            );",
        )
        .map_err(|error| error.to_string())
    }

    fn insert_synapse_note(
        conn: &Connection,
        id: &str,
        source: &str,
        confirmed_at: Option<i64>,
    ) -> Result<(), String> {
        conn.execute(
            "INSERT INTO notes (
                id, content, layer, is_active, evolution_state, source, confirmed_at
            ) VALUES (?1, ?2, 'verified_fact', 1, 'active', ?3, ?4)",
            params![id, format!("{id} content"), source, confirmed_at],
        )
        .map(|_| ())
        .map_err(|error| error.to_string())
    }

    fn synapse_relation_count(conn: &Connection, left: &str, right: &str) -> Result<i64, String> {
        conn.query_row(
            "SELECT COUNT(*) FROM note_relations
             WHERE ((from_note_id = ?1 AND to_note_id = ?2)
                 OR (from_note_id = ?2 AND to_note_id = ?1))
               AND relation_type = 'supports'",
            params![left, right],
            |row| row.get(0),
        )
        .map_err(|error| error.to_string())
    }

    #[test]
    fn trust_gate_synapse_skips_unconfirmed_ai_pair_and_keeps_user_pair() -> Result<(), String> {
        let conn = Connection::open_in_memory().map_err(|error| error.to_string())?;
        init_strengthen_prune_schema(&conn)?;
        insert_synapse_note(&conn, "ai-note", "ai", None)?;
        insert_synapse_note(&conn, "user-note", "user", None)?;
        insert_synapse_note(&conn, "user-peer", "user", None)?;

        for _ in 0..2 {
            conn.execute(
                "INSERT INTO query_log (timestamp, top_result_ids)
                 VALUES ('2026-05-19T00:00:00+00:00', '[\"ai-note\", \"user-note\", \"user-peer\"]')",
                [],
            )
            .map_err(|error| error.to_string())?;
        }

        let report = run_synapse_hebbian(&conn, 10, true).map_err(|error| error.to_string())?;

        assert_eq!(report["created"], json!(1));
        assert_eq!(synapse_relation_count(&conn, "ai-note", "user-note")?, 0);
        assert_eq!(synapse_relation_count(&conn, "ai-note", "user-peer")?, 0);
        assert_eq!(synapse_relation_count(&conn, "user-note", "user-peer")?, 1);
        Ok(())
    }

