    #[test]
    fn consolidate_reality_path_apply_marks_dead_paths() -> Result<(), String> {
        let dir = temp_dir("reality-path")?;
        let db_path = dir.join("memory_anchor.sqlite3");
        let alive_path = dir.join("alive.txt");
        fs::write(&alive_path, "alive").map_err(|error| error.to_string())?;
        let missing_path = dir.join("missing.txt");
        bootstrap_database(&db_path).map_err(|error| error.to_string())?;
        let conn = Connection::open(&db_path).map_err(|error| error.to_string())?;
        conn.execute(
            "INSERT INTO notes (
                id, content, layer, project_id, is_active, confidence, metadata_json, created_at, updated_at
             ) VALUES (?1, ?2, 'verified_fact', 'alpha', 1, 0.9, '{\"kept\":true}', ?3, ?3)",
            params![
                "dead-path-note",
                format!(
                    "Check {} and {} before launch.",
                    alive_path.display(),
                    missing_path.display()
                ),
                "2026-05-01T00:00:00+00:00",
            ],
        )
        .map_err(|error| error.to_string())?;
        conn.execute(
            "INSERT INTO notes (
                id, content, layer, project_id, is_active, confidence, created_at, updated_at
             ) VALUES ('identity', '/tmp/missing-identity.txt', 'identity_schema', 'alpha', 1, 1.0, ?1, ?1)",
            params!["2026-05-01T00:00:00+00:00"],
        )
        .map_err(|error| error.to_string())?;
        let run_at = chrono::DateTime::parse_from_rfc3339("2026-05-15T00:00:00+00:00")
            .map_err(|error| error.to_string())?
            .with_timezone(&Utc);

        let report = detect_reality_dead_paths(&conn, true, 50, run_at)
            .map_err(|error| error.to_string())?;
        assert_eq!(report["candidates_with_dead_paths"], json!(1));
        assert_eq!(report["updated"], json!(1));
        assert_eq!(
            report["details"][0]["dead_paths"],
            json!([missing_path.display().to_string()])
        );
        let metadata: String = conn
            .query_row(
                "SELECT metadata_json FROM notes WHERE id = 'dead-path-note'",
                [],
                |row| row.get(0),
            )
            .map_err(|error| error.to_string())?;
        let metadata: Value = serde_json::from_str(&metadata).map_err(|error| error.to_string())?;
        assert_eq!(metadata["kept"], json!(true));
        assert_eq!(metadata["reality_check_failed"], json!("dead_paths"));
        assert_eq!(
            metadata["dead_paths"],
            json!([missing_path.display().to_string()])
        );
        let event_count: i64 = conn
            .query_row(
                "SELECT COUNT(*) FROM note_events
                 WHERE note_id = 'dead-path-note' AND event_type = 'reality_check_dead_path'",
                [],
                |row| row.get(0),
            )
            .map_err(|error| error.to_string())?;
        assert_eq!(event_count, 1);
        Ok(())
    }

