    #[test]
    fn llm_smoke_reports_missing_key_without_network() -> Result<(), String> {
        let parsed = Cli::try_parse_from([
            "ma",
            "llm",
            "smoke",
            "--provider",
            "deepseek",
            "--api-key-env",
            "MA_R3_SMOKE_TEST_MISSING_KEY",
            "--akm-key",
            "MA_R3_SMOKE_TEST_MISSING_KEY",
            "--akm-bin",
            "/definitely/missing/akm",
        ])
        .map_err(|error| error.to_string())?;
        let command = parsed.into_command();
        let smoke = match &command {
            Command::Llm(args) => match args.command() {
                LlmCommand::Smoke(smoke) => smoke,
            },
            other => return Err(format!("expected llm smoke, got {other:?}")),
        };

        let report = build_llm_smoke_report(smoke).map_err(|error| error.to_string())?;

        assert_eq!(report.results.len(), 1);
        assert_eq!(report.results[0].provider, "deepseek");
        assert_eq!(report.results[0].status, "missing_key");
        assert_eq!(report.results[0].key_env, "MA_R3_SMOKE_TEST_MISSING_KEY");
        assert!(report.results[0].error.is_some());
        assert!(!report.passed());
        Ok(())
    }

    #[test]
    fn llm_smoke_real_key_path_reports_failure_inside_existing_runtime() -> Result<(), String> {
        let old_key = env::var("MA_R3_SMOKE_TEST_KEY").ok();
        unsafe {
            env::set_var("MA_R3_SMOKE_TEST_KEY", "test-key-never-sent");
        }
        let parsed = Cli::try_parse_from([
            "ma",
            "llm",
            "smoke",
            "--provider",
            "openai",
            "--api-base",
            "http://127.0.0.1:9",
            "--api-key-env",
            "MA_R3_SMOKE_TEST_KEY",
            "--akm-bin",
            "/definitely/missing/akm",
            "--json",
        ])
        .map_err(|error| error.to_string())?;
        let command = parsed.into_command();
        let smoke = match &command {
            Command::Llm(args) => match args.command() {
                LlmCommand::Smoke(smoke) => smoke,
            },
            other => return Err(format!("expected llm smoke, got {other:?}")),
        };

        let report = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
            let runtime = tokio::runtime::Builder::new_current_thread()
                .enable_all()
                .build()
                .map_err(|error| error.to_string())?;
            runtime.block_on(async {
                build_llm_smoke_report(smoke).map_err(|error| error.to_string())
            })
        }));
        match old_key {
            Some(value) => unsafe {
                env::set_var("MA_R3_SMOKE_TEST_KEY", value);
            },
            None => unsafe {
                env::remove_var("MA_R3_SMOKE_TEST_KEY");
            },
        }
        let report = report
            .map_err(|_| "build_llm_smoke_report panicked inside existing runtime".to_string())??;

        assert_eq!(report.results.len(), 1);
        assert_eq!(report.results[0].provider, "openai");
        assert_eq!(report.results[0].status, "failed");
        let error = report.results[0]
            .error
            .as_deref()
            .ok_or_else(|| "expected connection error".to_string())?;
        assert!(!error.contains("Cannot start a runtime"));
        assert!(!report.passed());
        Ok(())
    }

    #[test]
    fn llm_smoke_uses_provider_specific_akm_key_env() -> Result<(), String> {
        let old_alias = env::var("MA_GEMINI_AKM_KEY").ok();
        unsafe {
            env::set_var("MA_GEMINI_AKM_KEY", "GEMINI_API_KEY_13");
        }
        let parsed = Cli::try_parse_from(["ma", "llm", "smoke", "--provider", "gemini"])
            .map_err(|error| error.to_string())?;
        let command = parsed.into_command();
        let smoke = match &command {
            Command::Llm(args) => match args.command() {
                LlmCommand::Smoke(smoke) => smoke,
            },
            other => return Err(format!("expected llm smoke, got {other:?}")),
        };

        let spec = llm_smoke_spec(LlmSmokeProvider::Gemini, smoke);
        match old_alias {
            Some(value) => unsafe {
                env::set_var("MA_GEMINI_AKM_KEY", value);
            },
            None => unsafe {
                env::remove_var("MA_GEMINI_AKM_KEY");
            },
        }

        assert_eq!(spec.key_env, "GEMINI_API_KEY");
        assert_eq!(spec.akm_key, "GEMINI_API_KEY_13");
        Ok(())
    }

