    #[test]
    fn consolidate_dream_evolve_apply_writes_log_and_config() -> Result<(), String> {
        let dir = temp_dir("dream-evolve-apply")?;
        let db_path = dir.join("memory_anchor.sqlite3");
        let config_path = dir.join("reflector_config.yaml");
        bootstrap_database(&db_path).map_err(|error| error.to_string())?;
        let conn = Connection::open(&db_path).map_err(|error| error.to_string())?;
        conn.execute(
            "INSERT INTO notes (id, content, layer, project_id, is_active, confidence, metadata_json)
             VALUES
             ('confirmed-note', 'confirmed dream', 'verified_fact', 'alpha', 1, 0.9, '{\"success_count\":1}'),
             ('corrected-note', 'corrected dream', 'verified_fact', 'alpha', 1, 0.9, '{\"failure_count\":1}')",
            [],
        )
        .map_err(|error| error.to_string())?;
        conn.execute(
            "INSERT INTO dream_candidates
             (id, project_id, source_type, summary, confidence, verdict, promoted_to, created_at, promoted_at)
             VALUES
             ('dream-confirmed', 'alpha', 'consolidation', 'confirmed', 0.9, 'promoted', 'confirmed-note',
              '2026-05-09T00:00:00+00:00', '2026-05-09T00:00:01+00:00'),
             ('dream-corrected', 'alpha', 'consolidation', 'corrected', 0.9, 'promoted', 'corrected-note',
              '2026-05-09T00:00:00+00:00', '2026-05-09T00:00:02+00:00')",
            [],
        )
        .map_err(|error| error.to_string())?;
        drop(conn);

        let run_at = chrono::DateTime::parse_from_rfc3339("2026-05-10T00:00:00+00:00")
            .map_err(|error| error.to_string())?
            .with_timezone(&Utc);
        let report = run_dream_evolver(&db_path, &config_path, "alpha", 7, true, run_at)
            .map_err(|error| error.to_string())?;
        assert_eq!(report["status"], json!("ok"));
        assert_eq!(report["summary"]["feedback_count"], json!(2));
        assert_eq!(report["summary"]["precision_rate"], json!(0.5));
        assert!(report["evolution_log_id"].as_str().is_some());
        let conn = Connection::open(&db_path).map_err(|error| error.to_string())?;
        let row: (i64, f64, String) = conn
            .query_row(
                "SELECT promoted_count, precision_rate, weight_adjustments FROM dream_evolution_log",
                [],
                |row| Ok((row.get(0)?, row.get(1)?, row.get(2)?)),
            )
            .map_err(|error| error.to_string())?;
        assert_eq!(row.0, 2);
        assert!((row.1 - 0.5).abs() < f64::EPSILON);
        let adjustment: Value = serde_json::from_str(&row.2).map_err(|error| error.to_string())?;
        assert_eq!(adjustment["status"], json!("adjusted"));
        let config_raw = fs::read_to_string(&config_path).map_err(|error| error.to_string())?;
        let config: Value = serde_yaml::from_str(&config_raw).map_err(|error| error.to_string())?;
        assert_eq!(config["reflector"]["last_precision_rate"], json!(0.5));
        assert_eq!(
            config["reflector"]["last_evolution_log_id"],
            report["evolution_log_id"]
        );
        Ok(())
    }

    #[test]
    fn consolidate_build_summary_matches_nightly_python_contract() -> Result<(), String> {
        let dir = temp_dir("consolidate-summary")?;
        let summary_tsv = dir.join("orchestration.tsv");
        let summary_json = dir.join("orchestration.json");
        let stage6_summary = dir.join("stage6.json");
        fs::write(
            &summary_tsv,
            "phase1_strengthen_prune\tpassed\t0\t12\t/tmp/strengthen.json\n\
             phase6_consolidation\tdegraded\t2\t34\t/tmp/consolidation.json\n\
             phase9_dream\tskipped\t0\t0\t/tmp/dream.json\n",
        )
        .map_err(|error| error.to_string())?;
        fs::write(
            &stage6_summary,
            serde_json::to_string(&json!({
                "fallback_stats": {
                    "event_writer_missing": 1,
                    "procedure_writer_missing": 0
                },
                "runtime_truth": {"writer": "rust"}
            }))
            .map_err(|error| error.to_string())?,
        )
        .map_err(|error| error.to_string())?;

        let parsed = Cli::try_parse_from([
            "ma",
            "consolidate",
            "build-summary",
            "--summary-tsv",
            summary_tsv.to_str().unwrap(),
            "--summary-json",
            summary_json.to_str().unwrap(),
            "--stage6-summary",
            stage6_summary.to_str().unwrap(),
        ])
        .map_err(|error| error.to_string())?;

        let report = match parsed.into_command() {
            Command::Consolidate(args) => match args.command() {
                ConsolidateCommand::BuildSummary(summary_args) => {
                    build_consolidation_summary_with_alert_config(
                        summary_args,
                        "warn".to_string(),
                        BTreeMap::from([
                            ("event_writer_missing".to_string(), 0),
                            ("event_writer_error_fallback".to_string(), 0),
                            ("procedure_writer_missing".to_string(), 0),
                            ("procedure_writer_error_fallback".to_string(), 0),
                        ]),
                    )
                    .map_err(|error| error.to_string())?
                }
                other => return Err(format!("expected consolidate build-summary, got {other:?}")),
            },
            other => return Err(format!("expected consolidate command, got {other:?}")),
        };

        assert_eq!(report.overall_status, "failed");
        assert_eq!(report.failed_stage_count, 1);
        assert_eq!(report.stages.len(), 3);
        assert_eq!(report.stages[1].stage, "phase6_consolidation");
        assert_eq!(report.stages[1].status, "degraded");
        assert_eq!(
            report.stages[1].fallback_stats.as_ref(),
            Some(&json!({"event_writer_missing": 1, "procedure_writer_missing": 0}))
        );
        assert_eq!(
            report.phase6_observability.summary_path,
            stage6_summary.display().to_string()
        );
        assert_eq!(report.phase6_observability.alert_mode, "warn");
        assert!(report.phase6_observability.threshold_breached);
        assert_eq!(report.phase6_observability.alert_count, 1);
        assert_eq!(
            report.phase6_observability.alerts[0].metric,
            "event_writer_missing"
        );
        assert_eq!(report.phase6_observability.alerts[0].actual, 1);
        assert_eq!(report.phase6_observability.alerts[0].threshold, 0);
        assert_eq!(
            report.phase6_observability.runtime_truth,
            json!({"writer": "rust"})
        );
        Ok(())
    }

