    #[test]
    fn runtime_drift_blocks_python_serve_when_rust_is_selected() -> Result<(), String> {
        let config_path = PathBuf::from("/tmp/memra-config.yaml");
        let servers = parse_server_processes(
            " 77 1 /repo/target/release/memra serve --project memra\n\
             88 1 /Users/x/.local/bin/uv --directory /repo run memra serve -p memra\n\
             89 88 /repo/.venv/bin/python /repo/.venv/bin/memra serve -p memra\n",
        );

        let snapshot = evaluate_runtime_snapshot(
            "memra",
            &config_path,
            Some("rust".to_string()),
            true,
            None,
            servers,
        );

        assert_eq!(snapshot.selected_backend, "rust");
        assert_eq!(snapshot.selected_source, "config");
        assert_eq!(snapshot.live_mcp_backend, "mixed");
        assert_eq!(snapshot.report.status, "blocked");
        assert_eq!(snapshot.report.stale_python_serve_process_count, 2);
        assert!(
            snapshot.report.reasons[0].contains("selected_backend=rust"),
            "{:?}",
            snapshot.report.reasons
        );
        Ok(())
    }

    #[test]
    fn runtime_drift_reports_parent_command_for_stale_python_serve() -> Result<(), String> {
        let raw = " 44 1 /Applications/Claude.app/Contents/MacOS/Claude\n\
                   88 44 /Users/x/.local/bin/uv --directory /repo run memra serve -p memra\n\
                   89 88 /repo/.venv/bin/python /repo/.venv/bin/memra serve -p memra\n";
        let mut servers = parse_server_processes(raw);
        attach_parent_commands(&mut servers, raw);

        let uv = servers
            .iter()
            .find(|server| server.pid == 88)
            .ok_or_else(|| "missing uv server".to_string())?;
        assert_eq!(
            uv.parent_command.as_deref(),
            Some("/Applications/Claude.app/Contents/MacOS/Claude")
        );
        let python = servers
            .iter()
            .find(|server| server.pid == 89)
            .ok_or_else(|| "missing python server".to_string())?;
        assert_eq!(
            python.parent_command.as_deref(),
            Some(
                "/Users/x/.local/bin/uv --directory /repo run memra serve -p memra"
            )
        );
        Ok(())
    }

    #[test]
    fn runtime_drift_reports_clean_rust_runtime() -> Result<(), String> {
        let config_path = PathBuf::from("/tmp/memra-config.yaml");
        let servers =
            parse_server_processes(" 77 1 /repo/target/release/memra serve --project memra\n");

        let snapshot =
            evaluate_runtime_snapshot("memra", &config_path, None, false, None, servers);

        assert_eq!(snapshot.selected_backend, "rust");
        assert_eq!(snapshot.selected_source, "default");
        assert_eq!(snapshot.live_mcp_backend, "rust");
        assert_eq!(snapshot.report.status, "pass");
        assert_eq!(snapshot.report.running_server_counts.get("rust"), Some(&1));
        Ok(())
    }

    #[test]
    fn runtime_backend_selection_matches_wrapper_priority() -> Result<(), String> {
        let (backend, source, env_backend) =
            resolve_backend_selection(Some("python"), true, Some("rust".to_string()));
        assert_eq!(
            (backend, source, env_backend.as_deref()),
            ("rust", "env", Some("rust"))
        );

        let (backend, source, env_backend) = resolve_backend_selection(Some("python"), true, None);
        assert_eq!((backend, source, env_backend), ("python", "config", None));

        let (backend, source, env_backend) =
            resolve_backend_selection(None, false, Some("invalid".to_string()));
        assert_eq!(
            (backend, source, env_backend.as_deref()),
            ("rust", "default", Some("invalid"))
        );
        Ok(())
    }

