    #[test]
    fn setup_installs_claude_config_and_hooks() -> Result<(), String> {
        let home = temp_dir("setup-install")?;
        let claude_config = home.join(".claude.json");
        let claude_settings = home.join(".claude/settings.json");
        let claude_config_arg = claude_config.to_string_lossy().to_string();
        let claude_settings_arg = claude_settings.to_string_lossy().to_string();
        let parsed = Cli::try_parse_from([
            "ma",
            "setup",
            "--project",
            "demo-project",
            "--install-precompact-hook",
            "--install-sessionstart-hook",
            "--json",
            "--claude-config",
            claude_config_arg.as_str(),
            "--claude-settings",
            claude_settings_arg.as_str(),
            "--bin-path",
            "/usr/local/bin/memra",
        ])
        .map_err(|error| error.to_string())?;
        let Command::Setup(args) = parsed.into_command() else {
            return Err("expected setup command".to_string());
        };

        let report = setup_claude_integration(&args).map_err(|error| error.to_string())?;
        assert_eq!(report["project"], json!("demo-project"));
        assert_eq!(report["mcp_config_action"], json!("added"));
        assert_eq!(report["precompact_hook"]["action"], json!("added"));
        assert_eq!(report["sessionstart_hook"]["action"], json!("added"));

        let mcp_config: Value = serde_json::from_str(
            &fs::read_to_string(&claude_config).map_err(|error| error.to_string())?,
        )
        .map_err(|error| error.to_string())?;
        assert_eq!(
            mcp_config["mcpServers"]["memra"]["command"],
            json!("/usr/local/bin/memra")
        );
        assert_eq!(
            mcp_config["mcpServers"]["memra"]["args"],
            json!(["serve", "--project", "demo-project"])
        );

        let settings: Value = serde_json::from_str(
            &fs::read_to_string(&claude_settings).map_err(|error| error.to_string())?,
        )
        .map_err(|error| error.to_string())?;
        assert_eq!(
            settings["hooks"]["PreCompact"][0]["hooks"][0]["command"],
            json!("/usr/local/bin/memra hook precompact --project demo-project")
        );
        assert_eq!(
            settings["hooks"]["PreCompact"][0]["hooks"][0]["timeout"],
            json!(15000)
        );
        assert_eq!(
            settings["hooks"]["SessionStart"][0]["hooks"][0]["command"],
            json!("/usr/local/bin/memra hook sessionstart --project demo-project")
        );
        Ok(())
    }

    #[test]
    fn setup_replaces_existing_memory_anchor_hooks() -> Result<(), String> {
        let home = temp_dir("setup-replace")?;
        let claude_config = home.join(".claude.json");
        let claude_settings = home.join(".claude/settings.json");
        fs::create_dir_all(claude_settings.parent().unwrap()).map_err(|error| error.to_string())?;
        fs::write(
            &claude_settings,
            serde_json::to_string_pretty(&json!({
                "hooks": {
                    "PreCompact": [
                        {
                            "matcher": "",
                            "hooks": [
                                {
                                    "type": "command",
                                    "command": "python3 /repo/scripts/compaction_flush.py --project old",
                                    "timeout": 15000,
                                }
                            ],
                        }
                    ],
                    "SessionStart": [
                        {
                            "matcher": "",
                            "hooks": [
                                {
                                    "type": "command",
                                    "command": "/venv/bin/python -m backend.cli hook sessionstart --project old",
                                    "timeout": 15000,
                                }
                            ],
                        }
                    ],
                }
            }))
            .map_err(|error| error.to_string())?,
        )
        .map_err(|error| error.to_string())?;

        let claude_config_arg = claude_config.to_string_lossy().to_string();
        let claude_settings_arg = claude_settings.to_string_lossy().to_string();
        let parsed = Cli::try_parse_from([
            "ma",
            "setup",
            "--project",
            "new",
            "--install-precompact-hook",
            "--install-sessionstart-hook",
            "--claude-config",
            claude_config_arg.as_str(),
            "--claude-settings",
            claude_settings_arg.as_str(),
            "--bin-path",
            "/bin/memra",
        ])
        .map_err(|error| error.to_string())?;
        let Command::Setup(args) = parsed.into_command() else {
            return Err("expected setup command".to_string());
        };

        let report = setup_claude_integration(&args).map_err(|error| error.to_string())?;
        assert_eq!(report["precompact_hook"]["action"], json!("updated"));
        assert_eq!(report["sessionstart_hook"]["action"], json!("updated"));

        let settings: Value = serde_json::from_str(
            &fs::read_to_string(&claude_settings).map_err(|error| error.to_string())?,
        )
        .map_err(|error| error.to_string())?;
        assert_eq!(settings["hooks"]["PreCompact"].as_array().unwrap().len(), 1);
        assert_eq!(
            settings["hooks"]["SessionStart"].as_array().unwrap().len(),
            1
        );
        assert_eq!(
            settings["hooks"]["PreCompact"][0]["hooks"][0]["command"],
            json!("/bin/memra hook precompact --project new")
        );
        assert_eq!(
            settings["hooks"]["SessionStart"][0]["hooks"][0]["command"],
            json!("/bin/memra hook sessionstart --project new")
        );
        let raw = fs::read_to_string(&claude_settings).map_err(|error| error.to_string())?;
        assert!(!raw.contains("compaction_flush.py"));
        assert!(!raw.contains("backend.cli"));
        Ok(())
    }

    #[test]
    fn setup_hook_predicates_match_historical_forms() {
        assert!(is_memory_anchor_precompact_command(
            "/usr/local/bin/memra hook precompact --project foo"
        ));
        assert!(is_memory_anchor_precompact_command(
            "/Users/dev/.venv/bin/python3 -m backend.cli hook precompact --project foo"
        ));
        assert!(is_memory_anchor_precompact_command(
            "python3 /repo/scripts/compaction_flush.py --project foo"
        ));
        assert!(!is_memory_anchor_precompact_command(
            "memra serve --project foo"
        ));
        assert!(is_memory_anchor_sessionstart_command(
            "memra hook sessionstart --project foo"
        ));
        assert!(is_memory_anchor_sessionstart_command(
            "python scripts/checkpoint.py load --project foo"
        ));
        assert!(!is_memory_anchor_sessionstart_command("/bin/echo hello"));
    }

