    #[test]
    fn batch_write_dream_commands_mutate_dream_tables() -> Result<(), String> {
        let dir = temp_dir("dream-batch-write")?;
        let db_path = dir.join("memory_anchor.sqlite3");
        bootstrap_database(&db_path).map_err(|error| error.to_string())?;
        let db = db_path.to_string_lossy().to_string();

        let insert = Cli::try_parse_from([
            "ma",
            "batch-write",
            "--project",
            "alpha",
            "--db",
            &db,
            "dream-insert-candidate",
            "--id",
            "dream-1",
            "--source-type",
            "consolidation",
            "--summary",
            "Rust writer owns dream candidates",
            "--confidence",
            "0.82",
            "--frequency",
            "3",
            "--evidence-ids-json",
            "[\"obs-1\",\"obs-2\"]",
            "--created-at",
            "2026-05-04T00:00:00Z",
        ])
        .map_err(|error| error.to_string())?;
        if let Command::BatchWrite(args) = insert.into_command() {
            let report = execute_batch_write(&args).map_err(|error| error.to_string())?;
            assert_eq!(report.status, "saved");
            assert_eq!(report.affected_rows, 1);
        } else {
            return Err("expected batch-write insert command".to_string());
        }

        let update = Cli::try_parse_from([
            "ma",
            "batch-write",
            "--project",
            "alpha",
            "--db",
            &db,
            "dream-update-candidate",
            "--candidate-id",
            "dream-1",
            "--verdict",
            "promoted",
            "--promoted-to",
            "note-1",
            "--promoted-at",
            "2026-05-04T00:01:00Z",
        ])
        .map_err(|error| error.to_string())?;
        if let Command::BatchWrite(args) = update.into_command() {
            let report = execute_batch_write(&args).map_err(|error| error.to_string())?;
            assert_eq!(report.affected_rows, 1);
        } else {
            return Err("expected batch-write update command".to_string());
        }

        let log = Cli::try_parse_from([
            "ma",
            "batch-write",
            "--project",
            "alpha",
            "--db",
            &db,
            "dream-evolution-log",
            "--id",
            "evo-1",
            "--run-at",
            "2026-05-04T00:02:00Z",
            "--period-start",
            "2026-05-03T00:02:00Z",
            "--period-end",
            "2026-05-04T00:02:00Z",
            "--promoted-count",
            "1",
            "--confirmed-count",
            "1",
            "--corrected-count",
            "0",
            "--outdated-count",
            "0",
            "--precision-rate",
            "1.0",
            "--weight-adjustments-json",
            "{\"status\":\"no_change\"}",
            "--discard-patterns-json",
            "[]",
            "--created-at",
            "2026-05-04T00:02:00Z",
        ])
        .map_err(|error| error.to_string())?;
        if let Command::BatchWrite(args) = log.into_command() {
            let report = execute_batch_write(&args).map_err(|error| error.to_string())?;
            assert_eq!(report.affected_rows, 1);
        } else {
            return Err("expected batch-write evolution command".to_string());
        }

        let conn = Connection::open(&db_path).map_err(|error| error.to_string())?;
        let candidate = conn
            .query_row(
                "SELECT project_id, verdict, promoted_to, evidence_ids
                 FROM dream_candidates WHERE id = 'dream-1'",
                [],
                |row| {
                    Ok((
                        row.get::<_, String>(0)?,
                        row.get::<_, String>(1)?,
                        row.get::<_, Option<String>>(2)?,
                        row.get::<_, Option<String>>(3)?,
                    ))
                },
            )
            .map_err(|error| error.to_string())?;
        assert_eq!(candidate.0, "alpha");
        assert_eq!(candidate.1, "promoted");
        assert_eq!(candidate.2.as_deref(), Some("note-1"));
        assert_eq!(candidate.3.as_deref(), Some("[\"obs-1\",\"obs-2\"]"));

        let evolution = conn
            .query_row(
                "SELECT project_id, promoted_count, precision_rate, weight_adjustments
                 FROM dream_evolution_log WHERE id = 'evo-1'",
                [],
                |row| {
                    Ok((
                        row.get::<_, String>(0)?,
                        row.get::<_, i64>(1)?,
                        row.get::<_, f64>(2)?,
                        row.get::<_, Option<String>>(3)?,
                    ))
                },
            )
            .map_err(|error| error.to_string())?;
        assert_eq!(evolution.0, "alpha");
        assert_eq!(evolution.1, 1);
        assert!((evolution.2 - 1.0).abs() < f64::EPSILON);
        assert_eq!(evolution.3.as_deref(), Some("{\"status\":\"no_change\"}"));
        Ok(())
    }

    #[test]
    fn batch_write_report_outcome_applies_feedback_loop() -> Result<(), String> {
        let dir = temp_dir("report-outcome")?;
        let db_path = dir.join("memory_anchor.sqlite3");
        bootstrap_database(&db_path).map_err(|error| error.to_string())?;
        let db = db_path.to_string_lossy().to_string();

        let conn = Connection::open(&db_path).map_err(|error| error.to_string())?;
        conn.execute(
            "INSERT INTO notes (id, content, layer, project_id, is_active, confidence)
             VALUES
             ('reported-note', 'promoted dream helped recall', 'verified_fact', 'alpha', 1, 0.90),
             ('related-note', 'related support', 'verified_fact', 'alpha', 1, 0.90)",
            [],
        )
        .map_err(|error| error.to_string())?;
        conn.execute(
            "INSERT INTO note_relations
             (from_note_id, to_note_id, relation_type, strength)
             VALUES ('related-note', 'reported-note', 'supports', 0.70)",
            [],
        )
        .map_err(|error| error.to_string())?;
        conn.execute(
            "INSERT INTO dream_candidates
             (id, project_id, source_type, summary, confidence, verdict, promoted_to, created_at, promoted_at)
             VALUES
             ('dream-feedback', 'alpha', 'real_recall_smoke', 'smoke fixture', 0.94, 'promoted',
              'reported-note', '2026-05-05T00:00:00Z', '2026-05-05T00:00:01Z')",
            [],
        )
        .map_err(|error| error.to_string())?;
        drop(conn);

        let parsed = Cli::try_parse_from([
            "ma",
            "batch-write",
            "--project",
            "alpha",
            "--db",
            &db,
            "report-outcome",
            "--memory-id",
            "reported-note",
            "--outcome",
            "confirmed",
            "--reason",
            "real recall smoke passed",
        ])
        .map_err(|error| error.to_string())?;
        let Command::BatchWrite(args) = parsed.into_command() else {
            return Err("expected batch-write report-outcome command".to_string());
        };
        let report = execute_batch_write(&args).map_err(|error| error.to_string())?;
        assert_eq!(report.status, "saved");
        assert_eq!(report.operation, "report_outcome");
        assert_eq!(report.note_id.as_deref(), Some("reported-note"));
        assert_eq!(report.action.as_deref(), Some("confirmed"));
        assert_eq!(report.affected_rows, 1);

        let conn = Connection::open(&db_path).map_err(|error| error.to_string())?;
        let (metadata, confidence, relation_strength, dream_confidence, writer_status): (
            String,
            f64,
            f64,
            f64,
            String,
        ) = conn
            .query_row(
                "SELECT n.metadata_json, n.confidence, nr.strength, dc.confidence, dc.writer_status
                 FROM notes n
                 JOIN note_relations nr ON nr.to_note_id = n.id
                 JOIN dream_candidates dc ON dc.promoted_to = n.id
                 WHERE n.id = 'reported-note'",
                [],
                |row| {
                    Ok((
                        row.get(0)?,
                        row.get(1)?,
                        row.get(2)?,
                        row.get(3)?,
                        row.get(4)?,
                    ))
                },
            )
            .map_err(|error| error.to_string())?;
        let metadata: Value = serde_json::from_str(&metadata).map_err(|error| error.to_string())?;
        assert_eq!(metadata["success_count"], json!(1));
        assert_eq!(metadata["failure_count"], json!(0));
        assert!((confidence - 0.91).abs() < f64::EPSILON);
        assert!((relation_strength - 0.75).abs() < f64::EPSILON);
        assert!((dream_confidence - 0.99).abs() < f64::EPSILON);
        assert_eq!(writer_status, "feedback_confirmed");
        Ok(())
    }

    #[test]
    fn dream_stats_count_project_candidates_and_precision() -> Result<(), String> {
        let conn = Connection::open_in_memory().map_err(|error| error.to_string())?;
        init_sqlite_schema(&conn).map_err(|error| error.to_string())?;
        let now = chrono::Utc::now().to_rfc3339();

        conn.execute(
            "INSERT INTO dream_candidates
             (id, project_id, source_type, summary, verdict, promoted_to, created_at, promoted_at)
             VALUES
             ('p1', 'alpha', 'consolidation', 'pending', 'pending', NULL, ?1, NULL),
             ('p2', 'alpha', 'consolidation', 'promoted', 'promoted', 'mem-confirmed', ?1, ?1),
             ('p3', 'alpha', 'consolidation', 'held', 'held', NULL, ?1, NULL),
             ('p4', 'alpha', 'consolidation', 'discarded', 'discarded', NULL, ?1, NULL),
             ('p5', 'alpha', 'consolidation', 'promoted due', 'promoted', 'mem-unreviewed', ?1, ?1),
             ('other', 'beta', 'consolidation', 'other', 'promoted', 'mem-other', ?1, ?1)",
            [&now],
        )
        .map_err(|error| error.to_string())?;
        conn.execute(
            "INSERT INTO notes (id, content, layer, project_id, is_active, metadata_json)
             VALUES
             ('mem-confirmed', 'confirmed dream', 'verified_fact', 'alpha', 1, '{\"success_count\":1}'),
             ('mem-unreviewed', 'unreviewed dream', 'verified_fact', 'alpha', 1, '{}'),
             ('mem-other', 'other project dream', 'verified_fact', 'beta', 1, '{\"failure_count\":1}')",
            [],
        )
        .map_err(|error| error.to_string())?;
        conn.execute(
            "INSERT INTO dream_evolution_log
             (id, project_id, run_at, period_start, period_end, precision_rate, created_at)
             VALUES
             ('e1', 'alpha', '2026-04-13T00:00:00Z', '2026-04-06T00:00:00Z', '2026-04-13T00:00:00Z', 0.5, ?1),
             ('e2', 'alpha', '2026-04-14T00:00:00Z', '2026-04-07T00:00:00Z', '2026-04-14T00:00:00Z', 0.75, ?1),
             ('e3', 'beta', '2026-04-14T00:00:00Z', '2026-04-07T00:00:00Z', '2026-04-14T00:00:00Z', 0.2, ?1)",
            [&now],
        )
        .map_err(|error| error.to_string())?;

        let stats = collect_dream_stats(&conn, "alpha").map_err(|error| error.to_string())?;
        assert_eq!(stats.candidates_total, 5);
        assert_eq!(stats.pending, 1);
        assert_eq!(stats.promoted, 2);
        assert_eq!(stats.held, 1);
        assert_eq!(stats.discarded, 1);
        assert_eq!(stats.promotions_last_7d, 2);
        assert_eq!(stats.feedback.confirmed, 1);
        assert_eq!(stats.feedback.due, 1);
        assert_eq!(stats.feedback.applied, 1);
        let precision = stats
            .latest_precision_rate
            .ok_or("expected latest precision rate")?;
        assert!((precision - 0.75).abs() < f64::EPSILON);
        Ok(())
    }

    #[test]
    fn dream_stats_tolerate_mixed_timezone_formats() -> Result<(), String> {
        // Stored timestamps may arrive as either `...Z` or `...+00:00`
        // depending on writer (Python `utc_now_iso()` vs Rust
        // `to_rfc3339()`). Plain string comparison treats `Z` (0x5A) as
        // greater than `+` (0x2B), so a `Z`-suffixed row just past the
        // 7-day cutoff would be silently excluded. `julianday()` normalizes
        // zone suffixes while preserving subsecond ordering.
        let conn = Connection::open_in_memory().map_err(|e| e.to_string())?;
        init_sqlite_schema(&conn).map_err(|e| e.to_string())?;

        let fresh_z =
            (Utc::now() - Duration::days(1)).to_rfc3339_opts(chrono::SecondsFormat::Secs, true); // ends with Z
        let old_plus = (Utc::now() - Duration::days(30)).to_rfc3339(); // +00:00
        let fresh_plus = (Utc::now() - Duration::days(2)).to_rfc3339(); // +00:00
        conn.execute(
            "INSERT INTO dream_candidates
             (id, project_id, source_type, summary, verdict, created_at, promoted_at)
             VALUES
             ('z_fresh', 'alpha', 'consolidation', 's', 'promoted', ?1, ?1),
             ('plus_old', 'alpha', 'consolidation', 's', 'promoted', ?2, ?2),
             ('plus_fresh', 'alpha', 'consolidation', 's', 'promoted', ?3, ?3)",
            params![fresh_z, old_plus, fresh_plus],
        )
        .map_err(|e| e.to_string())?;

        // Evolution log with mixed suffixes — latest should win regardless.
        conn.execute(
            "INSERT INTO dream_evolution_log
             (id, project_id, run_at, period_start, period_end, precision_rate, created_at)
             VALUES
             ('log_plus_old',  'alpha', '2026-03-01T00:00:00+00:00', '2026-02-22T00:00:00+00:00', '2026-03-01T00:00:00+00:00', 0.30, ?1),
             ('log_z_newer',   'alpha', '2026-04-10T00:00:00Z',      '2026-04-03T00:00:00Z',      '2026-04-10T00:00:00Z',      0.88, ?1)",
            [&fresh_plus],
        )
        .map_err(|e| e.to_string())?;

        let stats = collect_dream_stats(&conn, "alpha").map_err(|e| e.to_string())?;

        // Both fresh rows should count; the 30-day-old row should not —
        // regardless of which zone suffix it carries.
        assert_eq!(
            stats.promotions_last_7d, 2,
            "Z-suffixed fresh row must count alongside +00:00 fresh row; \
             mixed-suffix comparison returned {}",
            stats.promotions_last_7d
        );

        let precision = stats
            .latest_precision_rate
            .ok_or("expected latest precision_rate")?;
        assert!(
            (precision - 0.88).abs() < f64::EPSILON,
            "newest log_z_newer (0.88) must win even though its run_at uses \
             `Z` while the older row uses `+00:00`; got {precision}"
        );
        Ok(())
    }

    #[test]
    fn dream_stats_surface_db_errors_instead_of_silently_zeroing() -> Result<(), String> {
        // Regression: `collect_dream_stats` used to `.unwrap_or(0)` on the
        // count/7-day queries, so a permission / corruption error would be
        // indistinguishable from "no rows". Now it propagates via `?`.
        let conn = Connection::open_in_memory().map_err(|e| e.to_string())?;
        // Create a decoy `dream_candidates` table with the wrong schema — the
        // existence check passes but the column-aware queries will error out,
        // which is exactly the condition we want surfaced, not swallowed.
        conn.execute_batch("CREATE TABLE dream_candidates (wrong_shape INTEGER);")
            .map_err(|e| e.to_string())?;

        match collect_dream_stats(&conn, "alpha") {
            Ok(_) => Err("expected DB error to propagate, got Ok".to_string()),
            Err(_) => Ok(()),
        }
    }

