    #[test]
    fn review_queue_items_rank_and_render_pending_work() -> Result<(), String> {
        let conn = Connection::open_in_memory().map_err(|e| e.to_string())?;
        init_sqlite_schema(&conn).map_err(|e| e.to_string())?;
        conn.execute_batch(
            "CREATE TABLE meta_fact_candidates (
                id TEXT PRIMARY KEY,
                project_id TEXT NOT NULL,
                fact_a_id TEXT NOT NULL,
                fact_b_id TEXT NOT NULL,
                cosine_similarity REAL NOT NULL,
                fact_a_summary TEXT,
                fact_b_summary TEXT,
                detected_at TEXT,
                verdict TEXT
            );",
        )
        .map_err(|e| e.to_string())?;
        let now = Utc::now().to_rfc3339();

        conn.execute(
            "INSERT INTO meta_fact_candidates
             (id, project_id, fact_a_id, fact_b_id, cosine_similarity,
              fact_a_summary, fact_b_summary, detected_at, verdict)
             VALUES
             ('meta-low', 'alpha', 'a1', 'a2', 0.93, 'old duplicate', 'new duplicate', ?1, 'pending'),
             ('meta-top', 'alpha', 'a3', 'a4', 0.99, 'same fact A', 'same fact B', ?1, 'pending'),
             ('meta-rejected', 'alpha', 'a5', 'a6', 1.0, 'rejected', 'rejected', ?1, 'rejected')",
            [&now],
        )
        .map_err(|e| e.to_string())?;
        conn.execute(
            "INSERT INTO dream_candidates
             (id, project_id, source_type, source_id, summary, confidence, verdict, created_at)
             VALUES
             ('drift-top', 'alpha', 'replay_drift', 'fact-1', 'old fact is losing to newer context', 0.91, 'pending', ?1),
             ('drift-held', 'alpha', 'replay_drift', 'fact-2', 'held drift', 0.99, 'held', ?1)",
            [&now],
        )
        .map_err(|e| e.to_string())?;

        let items = collect_review_queue_items(&conn, "alpha", ReviewQueueSource::All, 3)
            .map_err(|e| e.to_string())?;
        assert_eq!(items.len(), 3);
        assert_eq!(items[0].id, "meta-top");
        assert_eq!(items[0].source, "meta_fact");
        assert!(items[0].summary.contains("same fact A"));
        assert!(items[0].recommended_command.contains("ma review-resolve"));
        assert!(
            !items[0].recommended_command.contains("ma review-queue"),
            "review candidates need a drain command, not a recursive list command"
        );
        assert_eq!(items[2].id, "drift-top");
        assert_eq!(items[2].primary_id.as_deref(), Some("fact-1"));
        assert!(items[2].recommended_command.contains("ma review-resolve"));

        let summary = collect_review_queue_stats(&conn, "alpha").map_err(|e| e.to_string())?;
        let report = ReviewQueueReport {
            project: "alpha".to_string(),
            db_path: ":memory:".to_string(),
            source: "all".to_string(),
            limit: 3,
            summary,
            items,
        };
        let rendered = render_review_queue(&report);
        assert!(rendered.contains("Memra Review Queue - alpha"));
        assert!(rendered.contains("meta_fact"));
        assert!(rendered.contains("replay_drift"));
        assert!(rendered.contains("next:"));
        assert!(
            rendered.lines().count() <= 40,
            "review queue should stay glanceable:\n{rendered}"
        );

        let json_value = serde_json::to_value(&report).map_err(|e| e.to_string())?;
        assert_eq!(json_value["summary"]["total_pending"].as_i64(), Some(3));
        assert_eq!(json_value["items"][0]["id"].as_str(), Some("meta-top"));
        Ok(())
    }

    #[test]
    fn review_resolve_drains_meta_fact_candidates_without_touching_notes() -> Result<(), String> {
        let conn = Connection::open_in_memory().map_err(|e| e.to_string())?;
        init_sqlite_schema(&conn).map_err(|e| e.to_string())?;
        conn.execute_batch(
            "CREATE TABLE meta_fact_candidates (
                id TEXT PRIMARY KEY,
                project_id TEXT NOT NULL,
                fact_a_id TEXT NOT NULL,
                fact_b_id TEXT NOT NULL,
                cosine_similarity REAL NOT NULL,
                fact_a_summary TEXT,
                fact_b_summary TEXT,
                detected_at TEXT,
                verdict TEXT DEFAULT 'pending',
                reviewed_at TEXT,
                merged_at TEXT,
                merged_into_id TEXT,
                rejected_reason TEXT
            );",
        )
        .map_err(|e| e.to_string())?;
        let now = Utc::now().to_rfc3339();
        conn.execute(
            "INSERT INTO notes (id, content, layer, project_id, is_active)
             VALUES ('a1', 'fact A', 'verified_fact', 'alpha', 1),
                    ('a2', 'fact B', 'verified_fact', 'alpha', 1)",
            [],
        )
        .map_err(|e| e.to_string())?;
        conn.execute(
            "INSERT INTO meta_fact_candidates
             (id, project_id, fact_a_id, fact_b_id, cosine_similarity, detected_at, verdict)
             VALUES
             ('meta-reject', 'alpha', 'a1', 'a2', 0.99, ?1, 'pending'),
             ('meta-merge', 'alpha', 'a1', 'a2', 1.00, ?1, 'pending')",
            [&now],
        )
        .map_err(|e| e.to_string())?;

        let reject = resolve_review_candidate(
            &conn,
            ReviewResolveRequest {
                project: "alpha",
                db_path: Path::new(":memory:"),
                source: ReviewResolveSource::MetaFact,
                id: "meta-reject",
                verdict: ReviewResolveVerdict::Reject,
                reason: Some("false duplicate"),
                merged_into: None,
            },
        )
        .map_err(|e| e.to_string())?;
        assert_eq!(reject.status, "resolved");
        assert_eq!(reject.stored_verdict, "rejected");
        assert_eq!(reject.affected_rows, 1);

        let merge = resolve_review_candidate(
            &conn,
            ReviewResolveRequest {
                project: "alpha",
                db_path: Path::new(":memory:"),
                source: ReviewResolveSource::MetaFact,
                id: "meta-merge",
                verdict: ReviewResolveVerdict::Merge,
                reason: Some("human selected canonical fact"),
                merged_into: Some("a1"),
            },
        )
        .map_err(|e| e.to_string())?;
        assert_eq!(merge.stored_verdict, "merged");
        assert_eq!(merge.merged_into.as_deref(), Some("a1"));

        let stats = collect_review_queue_stats(&conn, "alpha").map_err(|e| e.to_string())?;
        assert_eq!(stats.meta_fact_pending, 0);
        let row: (String, Option<String>, Option<String>, Option<String>) = conn
            .query_row(
                "SELECT verdict, reviewed_at, rejected_reason, merged_into_id
                 FROM meta_fact_candidates WHERE id = 'meta-reject'",
                [],
                |row| Ok((row.get(0)?, row.get(1)?, row.get(2)?, row.get(3)?)),
            )
            .map_err(|e| e.to_string())?;
        assert_eq!(row.0, "rejected");
        assert!(row.1.is_some());
        assert_eq!(row.2.as_deref(), Some("false duplicate"));
        assert!(row.3.is_none());

        let note_count: i64 = conn
            .query_row("SELECT COUNT(*) FROM notes", [], |row| row.get(0))
            .map_err(|e| e.to_string())?;
        assert_eq!(note_count, 2, "candidate review must not auto-merge notes");
        Ok(())
    }

    #[test]
    fn review_resolve_drains_replay_drift_candidates_with_audit_status() -> Result<(), String> {
        let conn = Connection::open_in_memory().map_err(|e| e.to_string())?;
        init_sqlite_schema(&conn).map_err(|e| e.to_string())?;
        let now = Utc::now().to_rfc3339();
        conn.execute(
            "INSERT INTO dream_candidates
             (id, project_id, source_type, source_id, summary, confidence, verdict, created_at)
             VALUES
             ('drift-ack', 'alpha', 'replay_drift', 'fact-1', 'expected drift', 0.95, 'pending', ?1),
             ('drift-outdated', 'alpha', 'replay_drift', 'fact-2', 'old fact is wrong', 0.93, 'pending', ?1)",
            [&now],
        )
        .map_err(|e| e.to_string())?;

        let ack = resolve_review_candidate(
            &conn,
            ReviewResolveRequest {
                project: "alpha",
                db_path: Path::new(":memory:"),
                source: ReviewResolveSource::ReplayDrift,
                id: "drift-ack",
                verdict: ReviewResolveVerdict::Acknowledge,
                reason: Some("expected after newer task state"),
                merged_into: None,
            },
        )
        .map_err(|e| e.to_string())?;
        assert_eq!(ack.stored_verdict, "held");

        let outdated = resolve_review_candidate(
            &conn,
            ReviewResolveRequest {
                project: "alpha",
                db_path: Path::new(":memory:"),
                source: ReviewResolveSource::ReplayDrift,
                id: "drift-outdated",
                verdict: ReviewResolveVerdict::Outdated,
                reason: Some("source fact should decay"),
                merged_into: None,
            },
        )
        .map_err(|e| e.to_string())?;
        assert_eq!(outdated.stored_verdict, "discarded");

        let stats = collect_review_queue_stats(&conn, "alpha").map_err(|e| e.to_string())?;
        assert_eq!(stats.replay_drift_pending, 0);
        let rows: Vec<(String, String, Option<String>, Option<String>)> = {
            let mut stmt = conn
                .prepare(
                    "SELECT id, verdict, writer_status, writer_reason
                     FROM dream_candidates
                     ORDER BY id",
                )
                .map_err(|e| e.to_string())?;
            stmt.query_map([], |row| {
                Ok((row.get(0)?, row.get(1)?, row.get(2)?, row.get(3)?))
            })
            .map_err(|e| e.to_string())?
            .collect::<Result<Vec<_>, _>>()
            .map_err(|e| e.to_string())?
        };
        assert_eq!(
            rows,
            vec![
                (
                    "drift-ack".to_string(),
                    "held".to_string(),
                    Some("review_acknowledged".to_string()),
                    Some("expected after newer task state".to_string())
                ),
                (
                    "drift-outdated".to_string(),
                    "discarded".to_string(),
                    Some("review_outdated".to_string()),
                    Some("source fact should decay".to_string())
                )
            ]
        );
        Ok(())
    }

