    #[test]
    fn batch_lane_inventory_classifies_python_batch_surfaces() {
        let inventory = collect_batch_lane_inventory();
        assert_eq!(inventory.total, 7);
        assert_eq!(inventory.allowed_batch, 2);
        assert_eq!(inventory.keep_python_batch, 4);
        assert_eq!(inventory.must_migrate, 0);
        assert_eq!(inventory.retire, 1);

        let names: BTreeSet<_> = inventory
            .lanes
            .iter()
            .map(|lane| lane.name.as_str())
            .collect();
        for required in [
            "dream_consolidation",
            "event_procedure_consolidation",
            "experience_refresh",
            "autoresearch",
            "daily_pulse",
            "hook_capture",
            "background_worker_orchestrator",
        ] {
            assert!(names.contains(required), "missing batch lane {required}");
        }

        let mutating_debt: Vec<_> = inventory
            .lanes
            .iter()
            .filter(|lane| lane.mutates_core_memory && lane.classification == "must_migrate")
            .map(|lane| lane.name.as_str())
            .collect();
        assert!(mutating_debt.is_empty());

        let background_lane = inventory
            .lanes
            .iter()
            .find(|lane| lane.name == "background_worker_orchestrator")
            .expect("missing background worker lane");
        assert_eq!(background_lane.classification, "retire");
        assert!(background_lane.next_action.contains("ma background run"));
    }

    #[test]
    fn bench_trend_stats_average_recent_summary_json() -> Result<(), String> {
        let dir = temp_dir("bench-trend")?;
        let recent_a = dir.join("2026-05-16-a");
        let recent_b = dir.join("2026-05-17-b");
        let old = dir.join("2026-05-01-old");
        fs::create_dir_all(&recent_a).map_err(|error| error.to_string())?;
        fs::create_dir_all(&recent_b).map_err(|error| error.to_string())?;
        fs::create_dir_all(&old).map_err(|error| error.to_string())?;
        fs::write(
            recent_a.join("summary.json"),
            r#"{
              "completed_at": "2026-05-16T12:00:00Z",
              "top1_mean": 4.5,
              "latency_ms": {"p95": 12.345}
            }"#,
        )
        .map_err(|error| error.to_string())?;
        fs::write(
            recent_b.join("summary.json"),
            r#"{
              "completed_at": "2026-05-17T11:00:00Z",
              "top1_mean": 5.0,
              "latency_ms": {"p95": 85.8}
            }"#,
        )
        .map_err(|error| error.to_string())?;
        fs::write(
            old.join("summary.json"),
            r#"{
              "completed_at": "2026-05-01T12:00:00Z",
              "top1_mean": 1.0,
              "latency_ms": {"p95": 999.0}
            }"#,
        )
        .map_err(|error| error.to_string())?;

        let now = DateTime::parse_from_rfc3339("2026-05-17T12:00:00Z")
            .map_err(|error| error.to_string())?
            .with_timezone(&Utc);
        let trend = collect_bench_trend_stats(&dir, now);
        assert_eq!(trend.summary_count_7d, 2);
        assert_eq!(trend.bench_top1_mean_7d_avg, Some(4.75));
        assert_eq!(trend.latest_top1_mean, Some(5.0));
        assert_eq!(trend.latest_latency_p95_ms, Some(85.8));

        let latest = trend
            .latest_completed_at
            .as_deref()
            .ok_or("expected latest completed_at")?;
        let latest = DateTime::parse_from_rfc3339(latest)
            .map_err(|error| error.to_string())?
            .with_timezone(&Utc);
        assert_eq!(
            latest,
            DateTime::parse_from_rfc3339("2026-05-17T11:00:00Z")
                .map_err(|error| error.to_string())?
                .with_timezone(&Utc)
        );
        Ok(())
    }

