    #[test]
    fn hook_precompact_renders_summary_hints_and_reflection() {
        let mut checkpoint = PreCompactCheckpoint {
            timestamp: "2026-05-15T12:34:56.123456".to_string(),
            project_id: "demo".to_string(),
            trigger: "PreCompact".to_string(),
            ports: vec![PreCompactPort {
                port: 3000,
                status: "listening".to_string(),
            }],
            git_status: PreCompactGitStatus {
                branch: Some("main".to_string()),
                uncommitted_changes: vec![
                    PreCompactGitChange {
                        status: "M".to_string(),
                        file: "src/lib.rs".to_string(),
                    },
                    PreCompactGitChange {
                        status: "A".to_string(),
                        file: "new.txt".to_string(),
                    },
                ],
                has_stash: true,
                ahead_behind: PreCompactAheadBehind {
                    ahead: 2,
                    behind: 0,
                },
            },
            todo_status: PreCompactTodoStatus {
                in_progress: vec![PreCompactTodoItem {
                    id: "t1".to_string(),
                    content: "finish precompact rust port with parity".to_string(),
                    priority: "high".to_string(),
                }],
                pending: Vec::new(),
                source: Some("/tmp/todos.json".to_string()),
            },
            recovery_hints: Vec::new(),
        };
        checkpoint.recovery_hints = generate_precompact_recovery_hints(&checkpoint);

        let output =
            render_precompact_output(&checkpoint, &["多次编辑: phase4.rs(3x)".to_string()]);

        assert!(output.contains("[PreCompact] Saved: 1 ports, 2 uncommitted, 1 todos"));
        assert!(output.contains("  - Git: 1 files modified"));
        assert!(output.contains("  - Git: stash pending"));
        assert!(output.contains("  - Git: 2 commits to push"));
        assert!(output.contains("  - Todo: finish precompact rust port with parity"));
        assert!(output.contains("  - Ports: :3000"));
        assert!(output.contains("⚠️ 检测到行为信号: 多次编辑: phase4.rs(3x)"));
    }

    #[test]
    fn hook_precompact_writes_checkpoint_and_clears_trackers() -> Result<(), String> {
        let cwd = temp_dir("precompact-checkpoint")?;
        let checkpoint = PreCompactCheckpoint {
            timestamp: "2026-05-15T12:34:56.123456".to_string(),
            project_id: "demo".to_string(),
            trigger: "PreCompact".to_string(),
            ports: Vec::new(),
            git_status: PreCompactGitStatus {
                branch: None,
                uncommitted_changes: Vec::new(),
                has_stash: false,
                ahead_behind: PreCompactAheadBehind {
                    ahead: 0,
                    behind: 0,
                },
            },
            todo_status: PreCompactTodoStatus {
                in_progress: Vec::new(),
                pending: Vec::new(),
                source: None,
            },
            recovery_hints: Vec::new(),
        };
        let path = cwd
            .join(".claude")
            .join("checkpoints")
            .join("demo_latest.json");
        fs::create_dir_all(path.parent().unwrap()).map_err(|error| error.to_string())?;
        write_precompact_checkpoint(&path, &checkpoint).map_err(|error| error.to_string())?;
        let written = fs::read_to_string(&path).map_err(|error| error.to_string())?;
        let parsed: PreCompactCheckpoint =
            serde_json::from_str(&written).map_err(|error| error.to_string())?;
        assert_eq!(parsed.project_id, "demo");
        assert_eq!(parsed.trigger, "PreCompact");

        let tmp_dir = temp_dir("precompact-trackers")?;
        let edit_path = session_tmp_path_in(&tmp_dir, "edit_tracker.jsonl", "abc/def");
        let fail_path = session_tmp_path_in(&tmp_dir, "fail_tracker.jsonl", "abc/def");
        fs::write(
            &edit_path,
            "{\"file\":\"/repo/phase4.rs\"}\n{\"file\":\"/repo/phase4.rs\"}\n{\"file\":\"/repo/phase4.rs\"}\n",
        )
        .map_err(|error| error.to_string())?;
        fs::write(
            &fail_path,
            "{\"skeleton\":\"cargo test\"}\n{\"skeleton\":\"cargo test\"}\n",
        )
        .map_err(|error| error.to_string())?;

        let signals = collect_precompact_thrash_signals(&tmp_dir, "abc/def");
        assert_eq!(
            signals,
            vec![
                "多次编辑: phase4.rs(3x)".to_string(),
                "重复失败: cargo test(2x)".to_string()
            ]
        );
        assert_eq!(
            fs::read_to_string(edit_path).map_err(|error| error.to_string())?,
            ""
        );
        assert_eq!(
            fs::read_to_string(fail_path).map_err(|error| error.to_string())?,
            ""
        );
        Ok(())
    }

