    #[test]
    fn hook_sessionstart_renders_checkpoint_and_rotates_hook_warnings() -> Result<(), String> {
        let cwd = temp_dir("sessionstart-checkpoint")?;
        let checkpoint_dir = cwd.join(".claude").join("checkpoints");
        fs::create_dir_all(&checkpoint_dir).map_err(|error| error.to_string())?;
        fs::write(
            checkpoint_dir.join("demo-project_latest.json"),
            json!({
                "timestamp": "2026-05-15T12:34:56.000000",
                "git": {"branch": "main", "modified": 8},
                "ports": [3000, 6333]
            })
            .to_string(),
        )
        .map_err(|error| error.to_string())?;

        let home = temp_dir("sessionstart-hook-home")?;
        let hook_dir = home.join(".memra").join("hook-errors");
        fs::create_dir_all(&hook_dir).map_err(|error| error.to_string())?;
        fs::write(hook_dir.join("precompact-a.json"), "{}").map_err(|error| error.to_string())?;
        fs::write(hook_dir.join("precompact-fatal.txt"), "boom\n")
            .map_err(|error| error.to_string())?;

        let payload = render_sessionstart_hook("demo-project", &cwd, &session_env(home))
            .map_err(|e| e.to_string())?;
        let context = payload["hookSpecificOutput"]["additionalContext"]
            .as_str()
            .unwrap_or_default();

        assert!(context.contains("Checkpoint 2026-05-15T12:"));
        assert!(context.contains("Git: main, 8 modified"));
        assert!(context.contains("Services: :3000, :6333"));
        assert!(context.contains("[Hook] WARNING: 2 PreCompact hook failures since last session"));
        assert!(hook_dir.join("read/precompact-a.json").is_file());
        assert!(hook_dir.join("read/precompact-fatal.txt").is_file());
        assert!(!hook_dir.join("precompact-a.json").exists());
        Ok(())
    }

    #[test]
    fn hook_sessionstart_renders_backup_disk_and_skill_summaries() -> Result<(), String> {
        let cwd = temp_dir("sessionstart-sidecars")?;
        let checkpoint_dir = cwd.join(".claude").join("checkpoints");
        fs::create_dir_all(&checkpoint_dir).map_err(|error| error.to_string())?;
        fs::write(
            checkpoint_dir.join("demo-project_latest.json"),
            json!({"timestamp": "2026-05-15T12:34:56Z", "git": {}, "ports": []}).to_string(),
        )
        .map_err(|error| error.to_string())?;

        let home = temp_dir("sessionstart-sidecars-home")?;
        let backup_dir = home.join(".memra").join("backup-errors");
        let disk_dir = home.join(".memra").join("disk-alerts");
        let skill_dir = home.join(".claude").join("skills").join("ma-procedures");
        fs::create_dir_all(&backup_dir).map_err(|error| error.to_string())?;
        fs::create_dir_all(&disk_dir).map_err(|error| error.to_string())?;
        fs::create_dir_all(&skill_dir).map_err(|error| error.to_string())?;
        fs::write(backup_dir.join("backup-a.json"), "{}").map_err(|error| error.to_string())?;
        fs::write(disk_dir.join("disk-a.json"), "{}").map_err(|error| error.to_string())?;
        fs::write(
            skill_dir.join("manifest.json"),
            json!({
                "generated_at": "2026-05-15T01:02:03Z",
                "entries": [{"name": "one"}, {"name": "two"}]
            })
            .to_string(),
        )
        .map_err(|error| error.to_string())?;

        let mut env = session_env(home);
        env.read_skills = Some("true".to_string());
        let payload =
            render_sessionstart_hook("demo-project", &cwd, &env).map_err(|e| e.to_string())?;
        let context = payload["hookSpecificOutput"]["additionalContext"]
            .as_str()
            .unwrap_or_default();

        assert!(context.contains("[Backup] WARNING: 1 nightly backup failure since last session"));
        assert!(context.contains("[Disk] WARNING: 1 disk-usage alert for ~/.memra/"));
        assert!(context.contains("[Skills] ma-procedures: 2 exported"));
        assert!(context.contains("generated 2026-05-15T01:"));
        assert!(backup_dir.join("read/backup-a.json").is_file());
        assert!(disk_dir.join("read/disk-a.json").is_file());
        Ok(())
    }

    fn create_dream_db(path: &Path) -> Result<(), String> {
        let conn = Connection::open(path).map_err(|error| error.to_string())?;
        ensure_dream_batch_tables(&conn).map_err(|error| error.to_string())
    }

    fn insert_dream_candidate(
        db_path: &Path,
        id: &str,
        summary: &str,
        verdict: &str,
        confidence: f64,
        created_at: &str,
    ) -> Result<(), String> {
        let conn = Connection::open(db_path).map_err(|error| error.to_string())?;
        conn.execute(
            "INSERT INTO dream_candidates
             (id, project_id, source_type, summary, confidence, verdict, created_at)
             VALUES (?1, 'memra', 'consolidation', ?2, ?3, ?4, ?5)",
            params![id, summary, confidence, verdict, created_at],
        )
        .map_err(|error| error.to_string())?;
        Ok(())
    }

