    #[test]
    fn research_aggregate_writes_python_shaped_jsonl() -> Result<(), String> {
        let dir = temp_dir("research-aggregate")?;
        let quality = dir.join("quality");
        let usage = dir.join("usage");
        fs::create_dir_all(quality.join("autoresearch")).map_err(|error| error.to_string())?;
        fs::create_dir_all(usage.join("autoresearch")).map_err(|error| error.to_string())?;
        fs::write(
            quality
                .join("autoresearch")
                .join("results-parallel-rust-candidate-mem-quality.tsv"),
            "commit\tmrr_at_5\tndcg_at_5\tstatus\tdescription\tsystem_score\tresume_score\tprocedure_transfer_score\tstaleness_score\tretrieval_score\tretrieval_guardrail_passed\ttrack\n\
             aaa111\t0.8500\t0.9600\tkeep\tquality win\t0.9700\t0.90\t0.80\t0.70\t0.85\ttrue\tmemory-quality\n\
             aaa222\t0.9000\t0.9700\tdiscard\tquality discard\t0.9900\t0.95\t0.95\t0.95\t0.90\ttrue\tmemory-quality\n",
        )
        .map_err(|error| error.to_string())?;
        fs::write(
            usage
                .join("autoresearch")
                .join("results-parallel-rust-candidate-mem-usage.tsv"),
            "commit\tmrr_at_5\tndcg_at_5\tstatus\tdescription\n\
             bbb111\t0.8800\t0.9600\tkeep\tlegacy usage win\n",
        )
        .map_err(|error| error.to_string())?;
        let out = dir.join("aggregate.jsonl");
        let quality_arg = format!("memory-quality={}", quality.display());
        let usage_arg = format!("memory-usage={}", usage.display());

        let parsed = Cli::try_parse_from([
            "ma",
            "research",
            "aggregate",
            "--tag",
            "rust-candidate",
            "--worktree",
            quality_arg.as_str(),
            "--worktree",
            usage_arg.as_str(),
            "--out",
            out.to_str().unwrap(),
            "--json",
        ])
        .map_err(|error| error.to_string())?;

        let result = match parsed.into_command() {
            Command::Research(args) => match args.command() {
                ResearchCommand::Aggregate(aggregate) => {
                    run_research_aggregate(aggregate).map_err(|error| error.to_string())?
                }
                other => return Err(format!("expected research aggregate, got {other:?}")),
            },
            other => return Err(format!("expected research command, got {other:?}")),
        };

        assert_eq!(result["status"], json!("aggregated"));
        assert_eq!(result["tag"], json!("rust-candidate"));
        assert_eq!(result["worker_count"], json!(2));
        let payload: Value = serde_json::from_str(
            fs::read_to_string(&out)
                .map_err(|error| error.to_string())?
                .trim(),
        )
        .map_err(|error| error.to_string())?;
        assert_eq!(payload["tag"], json!("rust-candidate"));
        assert_eq!(payload["workers"][0]["direction"], json!("memory-quality"));
        assert_eq!(payload["workers"][0]["best_commit"], json!("aaa111"));
        assert_eq!(payload["workers"][0]["best_system_score"], json!(0.97));
        assert_eq!(payload["workers"][1]["direction"], json!("memory-usage"));
        assert_eq!(payload["workers"][1]["best_commit"], json!("bbb111"));
        assert_eq!(payload["workers"][1]["best_system_score"], json!(0.0));
        assert_eq!(payload["workers"][1]["best_mrr"], json!(0.88));
        Ok(())
    }

