    #[test]
    fn dream_run_pending_executes_job_and_updates_state_without_python_wrapper()
    -> Result<(), String> {
        let dir = temp_dir("dream-run-pending-exec")?;
        let state_path = dir
            .join("demo")
            .join("workers")
            .join("auto-dream-state.json");
        let log_path = dir.join("dream.log");
        fs::create_dir_all(state_path.parent().unwrap()).map_err(|error| error.to_string())?;
        fs::write(
            &state_path,
            json!({
                "project_id": "demo",
                "sessions_since_last_dream": 3,
                "pending_job": {
                    "id": "job-exec",
                    "status": "pending",
                    "command_argv": ["/bin/sh", "-c", "printf dream-ok"],
                    "cwd": dir.display().to_string(),
                    "log_path": log_path.display().to_string(),
                    "timeout_seconds": 5
                }
            })
            .to_string(),
        )
        .map_err(|error| error.to_string())?;

        let parsed = Cli::try_parse_from([
            "ma",
            "dream",
            "run-pending",
            "--project",
            "demo",
            "--base-dir",
            dir.to_str().unwrap(),
            "--json",
        ])
        .map_err(|error| error.to_string())?;

        match parsed.into_command() {
            Command::Dream(args) => match args.command() {
                DreamCommand::RunPending(run) => {
                    let ran = run_auto_dream_pending(run).map_err(|error| error.to_string())?;
                    assert!(ran);
                }
                other => return Err(format!("expected run-pending command, got {other:?}")),
            },
            other => return Err(format!("expected dream command, got {other:?}")),
        }

        let state: Value = serde_json::from_str(
            &fs::read_to_string(&state_path).map_err(|error| error.to_string())?,
        )
        .map_err(|error| error.to_string())?;
        assert_eq!(state["pending_job"], Value::Null);
        assert_eq!(state["sessions_since_last_dream"], json!(0));
        assert_eq!(state["last_completed_job"]["id"], json!("job-exec"));
        assert_eq!(state["last_completed_job"]["status"], json!("completed"));
        assert_eq!(
            state["last_completed_job"]["rewritten_to_rust"],
            json!(false)
        );
        assert!(
            state["last_completed_job"]["dream_orchestration"]["summary"]
                .as_str()
                .unwrap_or("")
                .contains("已完成")
        );
        let report_path = state["last_completed_job"]["doc_refresh_report_path"]
            .as_str()
            .ok_or("missing doc refresh report path")?;
        let report = fs::read_to_string(report_path).map_err(|error| error.to_string())?;
        assert!(report.contains("Source: rust_auto_dream_run_pending"));
        let orchestrator_path = dir
            .join("demo")
            .join("workers")
            .join("auto-dream-orchestrator.json");
        let orchestrator: Value = serde_json::from_str(
            &fs::read_to_string(orchestrator_path).map_err(|error| error.to_string())?,
        )
        .map_err(|error| error.to_string())?;
        assert_eq!(orchestrator["last_completed_job_id"], json!("job-exec"));
        assert_eq!(
            orchestrator["job_history"][0]["current_stage"],
            json!("finalize")
        );
        assert_eq!(
            orchestrator["job_history"][0]["stage_history"][1]["status"],
            json!("completed")
        );
        assert_eq!(
            orchestrator["job_history"][0]["stage_history"][2]["status"],
            json!("completed")
        );
        assert_eq!(
            orchestrator["job_history"][0]["stage_history"][2]["metadata"]["artifact_count"],
            json!(1)
        );
        let log = fs::read_to_string(&log_path).map_err(|error| error.to_string())?;
        assert_eq!(log.trim(), "dream-ok");
        Ok(())
    }

