    #[test]
    fn dream_run_pending_rewrites_legacy_reality_check_job_to_rust_cli() -> Result<(), String> {
        let dir = temp_dir("dream-run-pending-rewrite")?;
        let parsed = Cli::try_parse_from([
            "ma",
            "dream",
            "run-pending",
            "--project",
            "demo",
            "--base-dir",
            dir.to_str().unwrap(),
        ])
        .map_err(|error| error.to_string())?;

        let run = match parsed.into_command() {
            Command::Dream(args) => match args.command() {
                DreamCommand::RunPending(run) => run.clone(),
                other => return Err(format!("expected run-pending command, got {other:?}")),
            },
            other => return Err(format!("expected dream command, got {other:?}")),
        };
        let job = json!({
            "command_argv": [
                "uv",
                "run",
                "python",
                "scripts/consolidate_reality_check.py",
                "--apply",
                "--max-per-phase",
                "30",
                "--llm-max",
                "10",
                "--project-dir",
                "/repo"
            ],
            "cwd": "/repo"
        });

        let (command, cwd, rewritten) =
            normalize_auto_dream_command(&run, &job).map_err(|error| error.to_string())?;

        assert!(rewritten);
        assert_eq!(command[1], "consolidate");
        assert_eq!(command[2], "reality-check");
        assert!(command.contains(&"--apply".to_string()));
        assert!(command.contains(&"--project-dir".to_string()));
        assert!(!command.iter().any(|part| part.contains("auto_dream.py")));
        assert!(!command.iter().any(|part| part == "python"));
        assert_eq!(cwd, PathBuf::from("/repo"));
        Ok(())
    }

    #[test]
    fn dream_pending_lists_only_shadow_candidates() -> Result<(), String> {
        let dir = temp_dir("dream-pending")?;
        let db = dir.join("dream.sqlite3");
        create_dream_db(&db)?;
        insert_dream_candidate(
            &db,
            "shadow-1",
            "Shadow candidate one",
            "shadow_pending",
            0.85,
            "2026-05-08T01:00:00+00:00",
        )?;
        insert_dream_candidate(
            &db,
            "shadow-2",
            "Shadow candidate two",
            "shadow_pending",
            0.90,
            "2026-05-08T01:00:00+00:00",
        )?;
        insert_dream_candidate(
            &db,
            "promoted-1",
            "Already promoted",
            "promoted",
            0.99,
            "2026-05-08T01:00:00+00:00",
        )?;

        let db_arg = db.display().to_string();
        let parsed = Cli::try_parse_from(["ma", "dream", "pending", "--db", db_arg.as_str()])
            .map_err(|error| error.to_string())?;
        let output = match parsed.into_command() {
            Command::Dream(args) => match args.command() {
                DreamCommand::Pending(pending) => {
                    render_dream_pending(pending).map_err(|error| error.to_string())?
                }
                other => return Err(format!("expected pending command, got {other:?}")),
            },
            other => return Err(format!("expected dream command, got {other:?}")),
        };

        assert!(output.contains("[dream pending] 2 shadow candidates"));
        assert!(output.contains("shadow-2 conf=0.90 | Shadow candidate two"));
        assert!(output.contains("shadow-1 conf=0.85 | Shadow candidate one"));
        assert!(!output.contains("promoted-1"));
        Ok(())
    }

