    #[test]
    fn dream_promote_zero_candidates_exits_clean() -> Result<(), String> {
        let dir = temp_dir("dream-promote-zero")?;
        let db = dir.join("dream.sqlite3");
        create_dream_db(&db)?;
        let db_arg = db.display().to_string();

        let parsed = Cli::try_parse_from([
            "ma",
            "dream",
            "promote",
            "2026-05-08",
            "--auto",
            "--db",
            db_arg.as_str(),
        ])
        .map_err(|error| error.to_string())?;
        let report = with_dream_auto_promote_env(Some("1"), || {
            let old_cold_storage = env::var("MA_COLD_STORAGE_ENABLED").ok();
            unsafe {
                env::set_var("MA_COLD_STORAGE_ENABLED", "false");
            }
            let result = match parsed.into_command() {
                Command::Dream(args) => match args.command() {
                    DreamCommand::Promote(promote) => {
                        execute_dream_promote(promote).map_err(|error| error.to_string())
                    }
                    other => Err(format!("expected promote command, got {other:?}")),
                },
                other => Err(format!("expected dream command, got {other:?}")),
            };
            match old_cold_storage {
                Some(value) => unsafe {
                    env::set_var("MA_COLD_STORAGE_ENABLED", value);
                },
                None => unsafe {
                    env::remove_var("MA_COLD_STORAGE_ENABLED");
                },
            }
            result
        })?;

        assert!(report.success);
        assert_eq!(
            report.output.trim(),
            "[dream promote] 0 shadow candidates match 2026-05-08"
        );
        Ok(())
    }

