    #[test]
    fn dream_promote_state_machine_matches_legacy_outcomes() -> Result<(), String> {
        let dir = temp_dir("dream-promote-state")?;
        let db = dir.join("dream.sqlite3");
        create_dream_db(&db)?;
        for (id, summary) in [
            ("abcdef0123", "Promotable candidate"),
            ("dupcand-x1y2", "Already exists in MA"),
            ("pendapp-q9", "Not durable yet"),
            ("polskip-z2", "Policy blocks this one"),
        ] {
            insert_dream_candidate(
                &db,
                id,
                summary,
                "shadow_pending",
                0.92,
                "2026-05-08T01:00:00+00:00",
            )?;
        }

        let rows = vec![
            DreamPromoteRow {
                id: "abcdef0123".to_string(),
                summary: "Promotable candidate".to_string(),
                confidence: 0.92,
            },
            DreamPromoteRow {
                id: "dupcand-x1y2".to_string(),
                summary: "Already exists in MA".to_string(),
                confidence: 0.92,
            },
            DreamPromoteRow {
                id: "pendapp-q9".to_string(),
                summary: "Not durable yet".to_string(),
                confidence: 0.92,
            },
            DreamPromoteRow {
                id: "polskip-z2".to_string(),
                summary: "Policy blocks this one".to_string(),
                confidence: 0.92,
            },
        ];
        let conn = Connection::open(&db).map_err(|error| error.to_string())?;
        let report = promote_dream_rows(&conn, &rows, |row| match row.id.as_str() {
            "abcdef0123" => DreamPromoteWriteResult::Saved {
                id: "mem-default".to_string(),
            },
            "dupcand-x1y2" => DreamPromoteWriteResult::Duplicate {
                existing_id: "mem-dup-existing".to_string(),
            },
            "pendapp-q9" => DreamPromoteWriteResult::PendingApproval,
            "polskip-z2" => DreamPromoteWriteResult::PolicySkipped {
                reason: "PII redaction triggered".to_string(),
            },
            other => DreamPromoteWriteResult::Failed {
                error: format!("unexpected id {other}"),
            },
        })
        .map_err(|error| error.to_string())?;

        assert!(report.success);
        assert!(report.output.contains("  [+] promoted abcdef01 → mem-defa"));
        assert!(
            report
                .output
                .contains("  [=] duplicate dupcand- → mem-dup- (cosine>0.88 dedup)")
        );
        assert!(
            report
                .output
                .contains("  [~] pending_approval pendapp- (held, not durable yet)")
        );
        assert!(
            report
                .output
                .contains("  [~] policy_skipped polskip-: PII redaction triggered")
        );
        assert!(
            report
                .output
                .contains("[dream promote] done: 1 promoted, 1 duplicates, 1 pending_approval, 1 policy_skipped, 0 failed")
        );

        let states = conn
            .prepare(
                "SELECT id, verdict, writer_status, promoted_to
                 FROM dream_candidates
                 ORDER BY id",
            )
            .map_err(|error| error.to_string())?
            .query_map([], |row| {
                Ok((
                    row.get::<_, String>(0)?,
                    row.get::<_, String>(1)?,
                    row.get::<_, Option<String>>(2)?,
                    row.get::<_, Option<String>>(3)?,
                ))
            })
            .map_err(|error| error.to_string())?
            .collect::<Result<Vec<_>, _>>()
            .map_err(|error| error.to_string())?;

        assert!(states.contains(&(
            "abcdef0123".to_string(),
            "promoted".to_string(),
            None,
            Some("mem-default".to_string())
        )));
        assert!(states.contains(&(
            "dupcand-x1y2".to_string(),
            "duplicate".to_string(),
            None,
            Some("mem-dup-existing".to_string())
        )));
        assert!(states.contains(&(
            "pendapp-q9".to_string(),
            "held".to_string(),
            Some("pending_approval".to_string()),
            None
        )));
        assert!(states.contains(&(
            "polskip-z2".to_string(),
            "held".to_string(),
            Some("policy_skipped".to_string()),
            None
        )));
        Ok(())
    }

